import { ParsedTrade, RawTrade, OptionType, TradeAction, ParsedSymbol, ClosedTrade, SummaryData, OpenPositionTracker } from '../types';

declare const Papa: any; // PapaParse is loaded via CDN

/**
 * Parses a numeric string from CSV, handling currency symbols, commas, and parentheses for negatives.
 * This is now robust enough to handle values that are already numbers.
 * @param value The string or number value to parse.
 * @returns The parsed number.
 */
function parseNumericValue(value: string | number): number {
  if (value === null || value === undefined) return 0;

  // Convert to string to handle both numbers (from Google Sheets) and strings (from CSV) uniformly.
  const stringValue = String(value);
  if (stringValue.trim() === '') return 0;

  let cleanValue = stringValue.replace(/[$,]/g, '').trim();
  let isNegative = false;
  if (cleanValue.startsWith('(') && cleanValue.endsWith(')')) {
    isNegative = true;
    cleanValue = cleanValue.substring(1, cleanValue.length - 1);
  }
  const num = parseFloat(cleanValue);

  if (isNaN(num)) {
      console.warn(`Could not parse numeric value: "${value}"`);
      return 0;
  }

  return isNegative ? -Math.abs(num) : num;
}


/**
 * Parses the complex option symbol string into structured data.
 * Example: 'TSLA 11/14/2025 430.00 P'
 * @param symbolString The symbol string from the CSV.
 * @returns ParsedSymbol object or null if parsing fails.
 */
export function parseSymbol(symbolString: string): ParsedSymbol | null {
  const parts = symbolString.split(' ');
  if (parts.length < 4) {
    // Not an option symbol, or malformed
    return null;
  }

  const stockName = parts[0];
  const optionDateStr = parts[1];
  const strikePriceStr = parts[2];
  const optionTypeChar = parts[3];

  const dateParts = optionDateStr.split('/');
  if (dateParts.length !== 3) {
      console.warn(`Skipping trade due to malformed date in symbol string: "${symbolString}"`);
      return null;
  }

  const [month, day, year] = dateParts.map(Number);

  // Basic check for valid numbers
  if (isNaN(month) || isNaN(day) || isNaN(year) || year < 1900 || year > 2100 || month < 1 || month > 12 || day < 1 || day > 31) {
      console.warn(`Skipping trade due to invalid date components in symbol string: "${symbolString}"`);
      return null;
  }

  // Date constructor for MM/DD/YYYY format
  const optionDate = new Date(year, month - 1, day); 

  if (isNaN(optionDate.getTime())) {
    console.warn(`Skipping trade due to invalid date created from symbol string: "${symbolString}"`);
    return null;
  }

  const strikePrice = parseFloat(strikePriceStr);
  const optionType = optionTypeChar === 'P' ? OptionType.PUT : OptionType.CALL;

  if (isNaN(strikePrice) || !Object.values(OptionType).includes(optionType)) {
    return null; // Invalid strike price or option type
  }

  const uniqueKey = `${stockName}-${optionDate.toISOString().split('T')[0]}-${strikePrice.toFixed(2)}-${optionType}`;

  return {
    stockName,
    optionDate,
    strikePrice,
    optionType,
    uniqueKey,
  };
}

/**
 * Parses the raw CSV data into a list of structured ParsedTrade objects.
 * Filters for 'Sell to Open', 'Buy to Close', 'Buy to Open', and 'Sell to Close' actions.
 * @param data An array of RawTrade objects from PapaParse.
 * @returns An array of ParsedTrade objects.
 */
export function parseTrades(data: RawTrade[]): ParsedTrade[] {
  const parsedTrades: ParsedTrade[] = [];
  let idCounter = 0;

  for (const rawTrade of data) {
    const action: TradeAction = rawTrade.Action as TradeAction;
    const relevantActions = [
      TradeAction.SELL_TO_OPEN, 
      TradeAction.BUY_TO_CLOSE, 
      TradeAction.BUY_TO_OPEN, 
      TradeAction.SELL_TO_CLOSE
    ];

    if (!relevantActions.includes(action)) {
      continue;
    }

    const symbolDetails = parseSymbol(rawTrade.Symbol);
    if (!symbolDetails) {
      continue;
    }

    // Robustly parse MM/DD/YYYY date format, ignoring any time component
    const dateStr = rawTrade.Date.split(' ')[0]; // Handle cases like "12/5/2025 15:59"
    const dateParts = dateStr.split('/');
    if (dateParts.length !== 3) {
        console.warn(`Skipping trade due to malformed date in 'Date' field: "${rawTrade.Date}"`, rawTrade);
        continue;
    }
    const [month, day, year] = dateParts.map(Number);
    if (isNaN(month) || isNaN(day) || isNaN(year) || year < 1900 || year > 2100 || month < 1 || month > 12 || day < 1 || day > 31) {
        console.warn(`Skipping trade due to invalid date components in 'Date' field: "${rawTrade.Date}"`, rawTrade);
        continue;
    }
    // Handles MM/DD/YYYY format robustly
    const originalDate = new Date(year, month - 1, day);
    if (isNaN(originalDate.getTime())) {
      console.warn(`Skipping trade due to invalid date created from 'Date' field: "${rawTrade.Date}"`, rawTrade);
      continue;
    }

    const quantity = parseNumericValue(rawTrade.Quantity);
    const tradePrice = parseNumericValue(rawTrade.Price);
    const fees = parseNumericValue(rawTrade['Fees & Comm']);
    const amount = parseNumericValue(rawTrade.Amount);

    if (quantity === 0) {
      console.warn(`Trade with zero quantity skipped: ${rawTrade.Symbol} on ${rawTrade.Date}`);
      continue;
    }

    parsedTrades.push({
      id: `trade-${idCounter++}`,
      ...symbolDetails,
      originalDate,
      action,
      quantity,
      tradePrice,
      fees,
      amount,
      account: rawTrade.Account || 'Default', // Add account, with a fallback
    });
  }
  return parsedTrades;
}


/**
 * Processes parsed trades to identify closed option positions and calculate P&L for both long and short trades.
 * @param parsedTrades An array of ParsedTrade objects.
 * @returns An object with closed trades, open positions, and unmatched closing trades.
 */
export function processClosedTrades(parsedTrades: ParsedTrade[]): { closedTrades: ClosedTrade[], openPositions: ParsedTrade[], unmatchedCloses: ParsedTrade[] } {
  const openShorts: Record<string, OpenPositionTracker[]> = {};
  const openLongs: Record<string, OpenPositionTracker[]> = {};
  const closedTrades: ClosedTrade[] = [];
  const unmatchedCloses: ParsedTrade[] = [];
  let closedTradeIdCounter = 0;

  parsedTrades.sort((a, b) => {
    const dateComparison = a.originalDate.getTime() - b.originalDate.getTime();
    if (dateComparison !== 0) return dateComparison;

    const actionOrder = (action: TradeAction) => {
      switch (action) {
        case TradeAction.SELL_TO_OPEN: return 1;
        case TradeAction.BUY_TO_OPEN: return 2;
        case TradeAction.BUY_TO_CLOSE: return 3;
        case TradeAction.SELL_TO_CLOSE: return 4;
        default: return 5;
      }
    };
    return actionOrder(a.action) - actionOrder(b.action);
  });

  // Reference date for expiration: Use the later of the last transaction or today's date.
  // This ensures that positions which expired after the last trade are correctly identified as closed.
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const lastTradeDate = parsedTrades.length > 0 ? parsedTrades[parsedTrades.length - 1].originalDate : today;
  const referenceDate = new Date(Math.max(lastTradeDate.getTime(), today.getTime()));

  for (const trade of parsedTrades) {
    // Handle opening trades
    if (trade.action === TradeAction.SELL_TO_OPEN) {
      if (!openShorts[trade.uniqueKey]) openShorts[trade.uniqueKey] = [];
      openShorts[trade.uniqueKey].push({ trade, remainingQuantity: trade.quantity });
    } else if (trade.action === TradeAction.BUY_TO_OPEN) {
      if (!openLongs[trade.uniqueKey]) openLongs[trade.uniqueKey] = [];
      openLongs[trade.uniqueKey].push({ trade, remainingQuantity: trade.quantity });
    }

    // Handle closing trades for SHORT positions
    else if (trade.action === TradeAction.BUY_TO_CLOSE) {
      let quantityToMatch = trade.quantity;
      const matchingOpenSells = openShorts[trade.uniqueKey];
      if (matchingOpenSells && matchingOpenSells.length > 0) {
        for (const openSell of matchingOpenSells) {
          if (quantityToMatch === 0) break;
          const matchedQuantity = Math.min(quantityToMatch, openSell.remainingQuantity);
          if (matchedQuantity > 0) {
            closedTrades.push(createClosedTrade(openSell.trade, trade, matchedQuantity, `closed-short-${closedTradeIdCounter++}`));
            openSell.remainingQuantity -= matchedQuantity;
            quantityToMatch -= matchedQuantity;
          }
        }
        openShorts[trade.uniqueKey] = matchingOpenSells.filter(t => t.remainingQuantity > 0);
        if (quantityToMatch > 0) unmatchedCloses.push({ ...trade, quantity: quantityToMatch });
      } else {
        unmatchedCloses.push(trade);
      }
    }

    // Handle closing trades for LONG positions
    else if (trade.action === TradeAction.SELL_TO_CLOSE) {
        let quantityToMatch = trade.quantity;
        const matchingOpenBuys = openLongs[trade.uniqueKey];
        if (matchingOpenBuys && matchingOpenBuys.length > 0) {
            for (const openBuy of matchingOpenBuys) {
                if (quantityToMatch === 0) break;
                const matchedQuantity = Math.min(quantityToMatch, openBuy.remainingQuantity);
                if (matchedQuantity > 0) {
                    // For long positions, the buy is the "original" and sell is the "close"
                    closedTrades.push(createClosedTrade(trade, openBuy.trade, matchedQuantity, `closed-long-${closedTradeIdCounter++}`));
                    openBuy.remainingQuantity -= matchedQuantity;
                    quantityToMatch -= matchedQuantity;
                }
            }
            openLongs[trade.uniqueKey] = matchingOpenBuys.filter(t => t.remainingQuantity > 0);
            if (quantityToMatch > 0) unmatchedCloses.push({ ...trade, quantity: quantityToMatch });
        } else {
            unmatchedCloses.push(trade);
        }
    }
  }

  // Process expired SHORT positions (max profit / assigned)
  // According to user request: expired Sell to Open is considered closed/matched.
  processExpiredPositions(openShorts, referenceDate, 'short', closedTrades);

  // Process expired LONG positions (max loss)
  processExpiredPositions(openLongs, referenceDate, 'long', closedTrades);

  const openPositions: ParsedTrade[] = [
    ...Object.values(openShorts).flat().map(tracker => ({ ...tracker.trade, quantity: tracker.remainingQuantity })),
    ...Object.values(openLongs).flat().map(tracker => ({ ...tracker.trade, quantity: tracker.remainingQuantity })),
  ].filter(t => t.quantity > 0);

  return { closedTrades, openPositions, unmatchedCloses };
}

function createClosedTrade(sellTrade: ParsedTrade, buyTrade: ParsedTrade, matchedQuantity: number, id: string): ClosedTrade {
  // Determine if this is a long or short position being closed.
  const isLongPosition = buyTrade.action === TradeAction.BUY_TO_OPEN && sellTrade.action === TradeAction.SELL_TO_CLOSE;
  const isShortPosition = sellTrade.action === TradeAction.SELL_TO_OPEN && buyTrade.action === TradeAction.BUY_TO_CLOSE;

  // Assign opening and closing trades based on the position type.
  const openingTrade = isLongPosition ? buyTrade : sellTrade;
  const closingTrade = isLongPosition ? sellTrade : buyTrade;

  const openDate = openingTrade.originalDate;
  const closeDate = closingTrade.originalDate;

  // P&L calculation is agnostic of position type because sell amount is positive and buy amount is negative.
  const pnlPerContractSell = sellTrade.amount / sellTrade.quantity;
  const pnlPerContractBuy = buyTrade.amount / buyTrade.quantity;
  const pnl = (pnlPerContractSell + pnlPerContractBuy) * matchedQuantity;

  const feesPerContractSell = sellTrade.fees / sellTrade.quantity;
  const feesPerContractBuy = buyTrade.fees / buyTrade.quantity;
  const netFees = (feesPerContractSell + feesPerContractBuy) * matchedQuantity;

  const timeDiff = closeDate.getTime() - openDate.getTime();
  let remainDays = Math.ceil(timeDiff / (1000 * 60 * 60 * 24));
  if (remainDays <= 0) remainDays = 1;

  let returnOnInvestment = 0;

  if (isLongPosition) {
    // For a long position, investment is the cost to open (buy). `buyTrade.amount` is negative.
    const investment = Math.abs((buyTrade.amount / buyTrade.quantity) * matchedQuantity);
    returnOnInvestment = investment !== 0 ? (pnl / investment) * 100 : 0;
  } 
  else if (isShortPosition) {
    // For a short position, return is based on collateral (strike price * 100 is a proxy).
    const collateral = (sellTrade.strikePrice * 100) * matchedQuantity;
    returnOnInvestment = collateral > 0 ? (pnl / collateral) * 100 : 0;
  }

  const annualizedReturnPercentage = returnOnInvestment * (365 / remainDays);

  return {
    id,
    sellTradeOriginal: sellTrade,
    buyTradeOriginal: buyTrade,
    matchedQuantity,
    pnl,
    netFees,
    returnPercentage: returnOnInvestment,
    remainDays,
    annualizedReturnPercentage,
    stockName: buyTrade.stockName,
    optionDate: buyTrade.optionDate,
    strikePrice: buyTrade.strikePrice,
    optionType: buyTrade.optionType,
    closeDate,
    account: buyTrade.account,
  };
}

function processExpiredPositions(
  openPositions: Record<string, OpenPositionTracker[]>,
  referenceDate: Date,
  positionType: 'long' | 'short',
  closedTrades: ClosedTrade[]
) {
  Object.values(openPositions).flat().forEach(tracker => {
    // Comparison is <= to capture positions expiring today.
    // If the option's expiry date is before or equal to the reference date, it is considered closed.
    if (tracker.remainingQuantity > 0 && tracker.trade.optionDate <= referenceDate) {
      const openTrade = tracker.trade;
      const matchedQuantity = tracker.remainingQuantity;

      if (positionType === 'short') { 
        // Expired short option (Sell to Open) is treated as max profit trade closed at $0.
        // This covers the user's requirement for "assigned" trades to be counted as closed.
        const syntheticBuy = { 
            ...openTrade, 
            originalDate: openTrade.optionDate, 
            tradePrice: 0, 
            fees: 0, 
            amount: 0, 
            quantity: matchedQuantity, 
            action: TradeAction.BUY_TO_CLOSE 
        };
        closedTrades.push(createClosedTrade(openTrade, syntheticBuy, matchedQuantity, `expired-short-${openTrade.id}`));
      } else { 
        // Expired long option (Buy to Open) is treated as a 100% loss trade closed at $0.
        const syntheticSell = { 
            ...openTrade, 
            originalDate: openTrade.optionDate, 
            tradePrice: 0, 
            fees: 0, 
            amount: 0, 
            quantity: matchedQuantity, 
            action: TradeAction.SELL_TO_CLOSE 
        };
        closedTrades.push(createClosedTrade(syntheticSell, openTrade, matchedQuantity, `expired-long-${openTrade.id}`));
      }
      tracker.remainingQuantity = 0; // Mark as processed so it doesn't stay in open positions.
    }
  });
}

export function calculateSummary(closedTrades: ClosedTrade[]): SummaryData {
  let totalPnL = 0;
  let winningTrades = 0;
  let losingTrades = 0;
  let maxProfit = 0;
  let maxLoss = 0;
  let totalReturnPercentage = 0;
  let totalAnnualizedReturnPercentage = 0;
  let maxAnnualizedReturnPercentage = -Infinity;

  for (const trade of closedTrades) {
    totalPnL += trade.pnl;
    if (trade.pnl > 0) {
      winningTrades++;
      if (trade.pnl > maxProfit) maxProfit = trade.pnl;
    } else if (trade.pnl < 0) {
      losingTrades++;
      if (trade.pnl < maxLoss) maxLoss = trade.pnl;
    }
    totalReturnPercentage += trade.returnPercentage;
    totalAnnualizedReturnPercentage += trade.annualizedReturnPercentage;
    if (trade.annualizedReturnPercentage > maxAnnualizedReturnPercentage) {
      maxAnnualizedReturnPercentage = trade.annualizedReturnPercentage;
    }
  }

  const totalTrades = closedTrades.length;
  const averagePnLPerTrade = totalTrades > 0 ? totalPnL / totalTrades : 0;
  const averageReturnPercentage = totalTrades > 0 ? totalReturnPercentage / totalTrades : 0;
  const averageAnnualizedReturnPercentage = totalTrades > 0 ? totalAnnualizedReturnPercentage / totalTrades : 0;

  return {
    totalPnL,
    totalTrades,
    winningTrades,
    losingTrades,
    averagePnLPerTrade,
    averageReturnPercentage,
    averageAnnualizedReturnPercentage,
    maxAnnualizedReturnPercentage: totalTrades > 0 ? maxAnnualizedReturnPercentage : 0,
    maxProfit,
    maxLoss,
  };
}

import { ParsedTrade, RawTrade, OptionType, TradeAction, ParsedSymbol, ClosedTrade, SummaryData, OpenPositionTracker } from '../types';

declare const Papa: any; // PapaParse is loaded via CDN

/**
 * Parses a numeric string from CSV, handling currency symbols, commas, and parentheses for negatives.
 * This is now robust enough to handle values that are already numbers.
 * @param value The string or number value to parse.
 * @returns The parsed number.
 */
function parseNumericValue(value: string | number): number {
  if (value === null || value === undefined) return 0;

  // Convert to string to handle both numbers (from Google Sheets) and strings (from CSV) uniformly.
  const stringValue = String(value);
  if (stringValue.trim() === '') return 0;

  let cleanValue = stringValue.replace(/[$,]/g, '').trim();
  let isNegative = false;
  if (cleanValue.startsWith('(') && cleanValue.endsWith(')')) {
    isNegative = true;
    cleanValue = cleanValue.substring(1, cleanValue.length - 1);
  }
  const num = parseFloat(cleanValue);

  if (isNaN(num)) {
      console.warn(`Could not parse numeric value: "${value}"`);
      return 0;
  }

  return isNegative ? -Math.abs(num) : num;
}

/**
 * Robustly parses a date string into a Date object.
 * Handles MM/DD/YYYY, ISO, and standard Date strings.
 */
function robustParseDate(dateInput: any): Date | null {
  if (!dateInput) return null;

  // If it's already a date-like string from Google Sheets (ISO format)
  const d = new Date(dateInput);
  if (!isNaN(d.getTime())) {
    // Reset to midnight UTC to ensure consistency
    return new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
  }

  // Fallback for manual MM/DD/YYYY parsing if standard constructor fails or misinterprets
  if (typeof dateInput === 'string' && dateInput.includes('/')) {
    const parts = dateInput.split(' ')[0].split('/');
    if (parts.length === 3) {
      const [m, d, y] = parts.map(Number);
      const manualDate = new Date(Date.UTC(y, m - 1, d));
      if (!isNaN(manualDate.getTime())) return manualDate;
    }
  }

  return null;
}

/**
 * Parses the complex option symbol string into structured data.
 * Example: 'TSLA 11/14/2025 430.00 P'
 * @param symbolString The symbol string from the CSV.
 * @returns ParsedSymbol object or null if parsing fails.
 */
export function parseSymbol(symbolString: string): ParsedSymbol | null {
  if (!symbolString) return null;
  const parts = symbolString.split(' ');
  if (parts.length < 4) return null;

  const stockName = parts[0];
  const optionDateStr = parts[1];
  const strikePriceStr = parts[2];
  const optionTypeChar = parts[3];

  const optionDate = robustParseDate(optionDateStr);
  if (!optionDate) {
    console.warn(`Skipping trade due to invalid date in symbol: "${symbolString}"`);
    return null;
  }

  const strikePrice = parseFloat(strikePriceStr);
  const optionType = optionTypeChar === 'P' ? OptionType.PUT : OptionType.CALL;

  if (isNaN(strikePrice)) return null;

  const uniqueKey = `${stockName}-${optionDate.toISOString().split('T')[0]}-${strikePrice.toFixed(2)}-${optionType}`;

  return {
    stockName,
    optionDate,
    strikePrice,
    optionType,
    uniqueKey,
  };
}

/**
 * Parses the raw CSV data into a list of structured ParsedTrade objects.
 * Filters for 'Sell to Open', 'Buy to Close', 'Buy to Open', and 'Sell to Close' actions.
 * @param data An array of RawTrade objects from PapaParse or Google Sheets.
 * @returns An array of ParsedTrade objects.
 */
export function parseTrades(data: RawTrade[]): ParsedTrade[] {
  const parsedTrades: ParsedTrade[] = [];
  let idCounter = 0;

  for (const rawTrade of data) {
    const actionStr = String(rawTrade.Action).trim();
    const action: TradeAction = actionStr as TradeAction;

    const relevantActions = [
      TradeAction.SELL_TO_OPEN, 
      TradeAction.BUY_TO_CLOSE, 
      TradeAction.BUY_TO_OPEN, 
      TradeAction.SELL_TO_CLOSE
    ];

    if (!relevantActions.includes(action)) continue;

    const symbolDetails = parseSymbol(rawTrade.Symbol);
    if (!symbolDetails) continue;

    const originalDate = robustParseDate(rawTrade.Date);
    if (!originalDate) {
      console.warn(`Skipping trade due to invalid 'Date' field: "${rawTrade.Date}"`, rawTrade);
      continue;
    }

    const quantity = parseNumericValue(rawTrade.Quantity);
    const tradePrice = parseNumericValue(rawTrade.Price);
    const fees = parseNumericValue(rawTrade['Fees & Comm']);
    const amount = parseNumericValue(rawTrade.Amount);

    if (quantity === 0) continue;

    parsedTrades.push({
      id: `trade-${idCounter++}`,
      ...symbolDetails,
      originalDate,
      action,
      quantity,
      tradePrice,
      fees,
      amount,
      account: rawTrade.Account || 'Default',
    });
  }
  return parsedTrades;
}

/**
 * Processes parsed trades to identify closed option positions.
 */
export function processClosedTrades(parsedTrades: ParsedTrade[]): { closedTrades: ClosedTrade[], openPositions: ParsedTrade[], unmatchedCloses: ParsedTrade[] } {
  const openShorts: Record<string, OpenPositionTracker[]> = {};
  const openLongs: Record<string, OpenPositionTracker[]> = {};
  const closedTrades: ClosedTrade[] = [];
  const unmatchedCloses: ParsedTrade[] = [];
  let closedTradeIdCounter = 0;

  // Sorting ensures chronological processing
  parsedTrades.sort((a, b) => a.originalDate.getTime() - b.originalDate.getTime());

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const lastTradeDate = parsedTrades.length > 0 ? parsedTrades[parsedTrades.length - 1].originalDate : today;
  const referenceDate = new Date(Math.max(lastTradeDate.getTime(), today.getTime()));

  for (const trade of parsedTrades) {
    if (trade.action === TradeAction.SELL_TO_OPEN) {
      if (!openShorts[trade.uniqueKey]) openShorts[trade.uniqueKey] = [];
      openShorts[trade.uniqueKey].push({ trade, remainingQuantity: trade.quantity });
    } else if (trade.action === TradeAction.BUY_TO_OPEN) {
      if (!openLongs[trade.uniqueKey]) openLongs[trade.uniqueKey] = [];
      openLongs[trade.uniqueKey].push({ trade, remainingQuantity: trade.quantity });
    }
    else if (trade.action === TradeAction.BUY_TO_CLOSE) {
      let quantityToMatch = trade.quantity;
      const matchingOpenSells = openShorts[trade.uniqueKey];
      if (matchingOpenSells && matchingOpenSells.length > 0) {
        for (const openSell of matchingOpenSells) {
          if (quantityToMatch === 0) break;
          const matchedQuantity = Math.min(quantityToMatch, openSell.remainingQuantity);
          if (matchedQuantity > 0) {
            closedTrades.push(createClosedTrade(openSell.trade, trade, matchedQuantity, `closed-short-${closedTradeIdCounter++}`));
            openSell.remainingQuantity -= matchedQuantity;
            quantityToMatch -= matchedQuantity;
          }
        }
        openShorts[trade.uniqueKey] = matchingOpenSells.filter(t => t.remainingQuantity > 0);
        if (quantityToMatch > 0) unmatchedCloses.push({ ...trade, quantity: quantityToMatch });
      } else {
        unmatchedCloses.push(trade);
      }
    }
    else if (trade.action === TradeAction.SELL_TO_CLOSE) {
        let quantityToMatch = trade.quantity;
        const matchingOpenBuys = openLongs[trade.uniqueKey];
        if (matchingOpenBuys && matchingOpenBuys.length > 0) {
            for (const openBuy of matchingOpenBuys) {
                if (quantityToMatch === 0) break;
                const matchedQuantity = Math.min(quantityToMatch, openBuy.remainingQuantity);
                if (matchedQuantity > 0) {
                    closedTrades.push(createClosedTrade(trade, openBuy.trade, matchedQuantity, `closed-long-${closedTradeIdCounter++}`));
                    openBuy.remainingQuantity -= matchedQuantity;
                    quantityToMatch -= matchedQuantity;
                }
            }
            openLongs[trade.uniqueKey] = matchingOpenBuys.filter(t => t.remainingQuantity > 0);
            if (quantityToMatch > 0) unmatchedCloses.push({ ...trade, quantity: quantityToMatch });
        } else {
            unmatchedCloses.push(trade);
        }
    }
  }

  processExpiredPositions(openShorts, referenceDate, 'short', closedTrades);
  processExpiredPositions(openLongs, referenceDate, 'long', closedTrades);

  const openPositions: ParsedTrade[] = [
    ...Object.values(openShorts).flat().map(tracker => ({ ...tracker.trade, quantity: tracker.remainingQuantity })),
    ...Object.values(openLongs).flat().map(tracker => ({ ...tracker.trade, quantity: tracker.remainingQuantity })),
  ].filter(t => t.quantity > 0);

  return { closedTrades, openPositions, unmatchedCloses };
}

function createClosedTrade(sellTrade: ParsedTrade, buyTrade: ParsedTrade, matchedQuantity: number, id: string): ClosedTrade {
  const isLongPosition = buyTrade.action === TradeAction.BUY_TO_OPEN && sellTrade.action === TradeAction.SELL_TO_CLOSE;
  const openingTrade = isLongPosition ? buyTrade : sellTrade;
  const closingTrade = isLongPosition ? sellTrade : buyTrade;

  const openDate = openingTrade.originalDate;
  const closeDate = closingTrade.originalDate;

  const pnlPerContractSell = sellTrade.amount / sellTrade.quantity;
  const pnlPerContractBuy = buyTrade.amount / buyTrade.quantity;
  const pnl = (pnlPerContractSell + pnlPerContractBuy) * matchedQuantity;

  const feesPerContractSell = sellTrade.fees / sellTrade.quantity;
  const feesPerContractBuy = buyTrade.fees / buyTrade.quantity;
  const netFees = (feesPerContractSell + feesPerContractBuy) * matchedQuantity;

  const timeDiff = closeDate.getTime() - openDate.getTime();
  let remainDays = Math.ceil(timeDiff / (1000 * 60 * 60 * 24));
  if (remainDays <= 0) remainDays = 1;

  let returnOnInvestment = 0;
  if (isLongPosition) {
    const investment = Math.abs((buyTrade.amount / buyTrade.quantity) * matchedQuantity);
    returnOnInvestment = investment !== 0 ? (pnl / investment) * 100 : 0;
  } else {
    const collateral = (sellTrade.strikePrice * 100) * matchedQuantity;
    returnOnInvestment = collateral > 0 ? (pnl / collateral) * 100 : 0;
  }

  const annualizedReturnPercentage = returnOnInvestment * (365 / remainDays);

  return {
    id,
    sellTradeOriginal: sellTrade,
    buyTradeOriginal: buyTrade,
    matchedQuantity,
    pnl,
    netFees,
    returnPercentage: returnOnInvestment,
    remainDays,
    annualizedReturnPercentage,
    stockName: buyTrade.stockName,
    optionDate: buyTrade.optionDate,
    strikePrice: buyTrade.strikePrice,
    optionType: buyTrade.optionType,
    closeDate,
    account: buyTrade.account,
  };
}

function processExpiredPositions(
  openPositions: Record<string, OpenPositionTracker[]>,
  referenceDate: Date,
  positionType: 'long' | 'short',
  closedTrades: ClosedTrade[]
) {
  Object.values(openPositions).flat().forEach(tracker => {
    if (tracker.remainingQuantity > 0 && tracker.trade.optionDate <= referenceDate) {
      const openTrade = tracker.trade;
      const matchedQuantity = tracker.remainingQuantity;

      if (positionType === 'short') { 
        const syntheticBuy = { ...openTrade, originalDate: openTrade.optionDate, tradePrice: 0, fees: 0, amount: 0, quantity: matchedQuantity, action: TradeAction.BUY_TO_CLOSE };
        closedTrades.push(createClosedTrade(openTrade, syntheticBuy, matchedQuantity, `expired-short-${openTrade.id}`));
      } else { 
        const syntheticSell = { ...openTrade, originalDate: openTrade.optionDate, tradePrice: 0, fees: 0, amount: 0, quantity: matchedQuantity, action: TradeAction.SELL_TO_CLOSE };
        closedTrades.push(createClosedTrade(syntheticSell, openTrade, matchedQuantity, `expired-long-${openTrade.id}`));
      }
      tracker.remainingQuantity = 0;
    }
  });
}

export function calculateSummary(closedTrades: ClosedTrade[]): SummaryData {
  let totalPnL = 0;
  let winningTrades = 0;
  let losingTrades = 0;
  let maxProfit = 0;
  let maxLoss = 0;
  let totalReturnPercentage = 0;
  let totalAnnualizedReturnPercentage = 0;
  let maxAnnualizedReturnPercentage = -Infinity;

  for (const trade of closedTrades) {
    totalPnL += trade.pnl;
    if (trade.pnl > 0) {
      winningTrades++;
      if (trade.pnl > maxProfit) maxProfit = trade.pnl;
    } else if (trade.pnl < 0) {
      losingTrades++;
      if (trade.pnl < maxLoss) maxLoss = trade.pnl;
    }
    totalReturnPercentage += trade.returnPercentage;
    totalAnnualizedReturnPercentage += trade.annualizedReturnPercentage;
    if (trade.annualizedReturnPercentage > maxAnnualizedReturnPercentage) {
      maxAnnualizedReturnPercentage = trade.annualizedReturnPercentage;
    }
  }

  const totalTrades = closedTrades.length;
  return {
    totalPnL,
    totalTrades,
    winningTrades,
    losingTrades,
    averagePnLPerTrade: totalTrades > 0 ? totalPnL / totalTrades : 0,
    averageReturnPercentage: totalTrades > 0 ? totalReturnPercentage / totalTrades : 0,
    averageAnnualizedReturnPercentage: totalTrades > 0 ? totalAnnualizedReturnPercentage / totalTrades : 0,
    maxAnnualizedReturnPercentage: totalTrades > 0 ? maxAnnualizedReturnPercentage : 0,
    maxProfit,
    maxLoss,
  };
}

