import { CLIENT_ID, GOOGLE_APPS_SCRIPT_URL, SCOPES, GOOGLE_SHEET_HEADER } from './constants';
import { RawTrade } from '../types';

declare global {
  const google: any;
}

let tokenClient: any | null = null;

/**
 * Dynamically loads the Google Identity Services script and initializes the token client.
 */
export const initGoogleClient = (callback: (tokenResponse: any) => void): Promise<void> => {
  return new Promise((resolve, reject) => {
    const initialize = () => {
      try {
        if (!CLIENT_ID || CLIENT_ID.includes('YOUR_GOOGLE_OAUTH_CLIENT_ID')) {
          const errorMsg = "Google Client ID is not configured.";
          console.error(errorMsg);
          reject(new Error(errorMsg));
          return;
        }
        tokenClient = google.accounts.oauth2.initTokenClient({
          client_id: CLIENT_ID,
          scope: SCOPES,
          callback: callback,
        });
        resolve();
      } catch (error) {
        reject(error);
      }
    };

    if (typeof google !== 'undefined' && google?.accounts?.oauth2) {
      initialize();
      return;
    }

    const script = document.createElement('script');
    script.src = 'https://accounts.google.com/gsi/client';
    script.async = true;
    script.defer = true;
    script.onload = () => {
      if (typeof google === 'undefined') {
        reject(new Error('Google script loaded, but `google` object not found.'));
        return;
      }
      initialize();
    };
    script.onerror = () => reject(new Error('Failed to load Google script.'));
    document.body.appendChild(script);
  });
};

export const requestAccessToken = () => {
  if (tokenClient) {
    tokenClient.requestAccessToken({ prompt: '' });
  } else {
    alert('Google Authentication is not ready.');
  }
};

export const revokeAccessToken = (accessToken: string) => {
    if (accessToken && typeof google !== 'undefined' && google?.accounts?.oauth2) {
        google.accounts.oauth2.revoke(accessToken, () => {});
    }
}

export const fetchUserProfile = async (accessToken: string): Promise<{ email: string; name: string, picture: string }> => {
  const response = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', {
    headers: { 'Authorization': `Bearer ${accessToken}` }
  });
  if (!response.ok) throw new Error('Failed to fetch user profile.');
  return response.json();
};

/**
 * Helper to clean numeric strings for spreadsheet saving.
 * Handles currencies, commas, and parentheses for negatives.
 */
function cleanNumericForSheet(value: any): any {
    if (value === null || value === undefined) return 0;
    if (typeof value === 'number') return value;

    const str = String(value).trim();
    if (str === '') return 0;

    const isNegative = str.startsWith('(') && str.endsWith(')');
    const cleanStr = str.replace(/[$,()]/g, '');
    const num = parseFloat(cleanStr);

    if (isNaN(num)) return str; // Return as string if it's not actually a number
    return isNegative ? -Math.abs(num) : num;
}

/**
 * Sends the raw trade data to Google Sheet. 
 * Converts numeric columns to actual numbers to ensure spreadsheet compatibility.
 */
export const saveRawTradesToSheet = async (rawData: RawTrade[], accessToken: string): Promise<{ status: string; message: string }> => {
  if (!GOOGLE_APPS_SCRIPT_URL || GOOGLE_APPS_SCRIPT_URL.includes('...')) {
    throw new Error("Google Apps Script URL is not configured.");
  }

  if (rawData.length === 0) throw new Error("No data to save.");

  const headers = GOOGLE_SHEET_HEADER;
  const numericColumns = ["Quantity", "Price", "Fees & Comm", "Amount"];

  const rowsToSave = rawData.map(trade => {
    return headers.map(header => {
      const value = trade[header as keyof RawTrade];
      // Convert specific columns to numbers before saving
      if (numericColumns.includes(header)) {
        return cleanNumericForSheet(value);
      }
      return value;
    });
  });

  const payload = {
    header: headers,
    rows: rowsToSave,
  };

  const formData = new FormData();
  formData.append('payload', JSON.stringify(payload));

  const response = await fetch(GOOGLE_APPS_SCRIPT_URL, {
    method: 'POST',
    mode: 'cors',
    body: formData,
  });

  if (!response.ok) throw new Error(`Network response error: ${response.statusText}`);

  const result = await response.json();
  if (result.status === 'error') throw new Error(result.message);
  return result;
};

export const fetchRawTradesFromSheet = async (accessToken: string): Promise<RawTrade[]> => {
  if (!GOOGLE_APPS_SCRIPT_URL || GOOGLE_APPS_SCRIPT_URL.includes('...')) {
    throw new Error("Google Apps Script URL is not configured.");
  }

  const response = await fetch(GOOGLE_APPS_SCRIPT_URL, {
    method: 'GET',
    mode: 'cors',
    redirect: 'follow',
    cache: 'no-cache',
  });

  if (!response.ok) throw new Error(`Network error: ${response.statusText}`);
  const result = await response.json();
  if (result.status === 'error') throw new Error(result.message);
  return result.data as RawTrade[] || [];
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { RawTrade, ParsedTrade, ClosedTrade, SummaryData, OptionType } from './types';
import { parseTrades, processClosedTrades, calculateSummary } from './services/csvParser';
import { initGoogleClient, requestAccessToken, revokeAccessToken, fetchUserProfile, saveRawTradesToSheet, fetchRawTradesFromSheet } from './services/google';
import FileUpload from './components/FileUpload';
import SummaryCard from './components/SummaryCard';
import TradeTable from './components/TradeTable';
import PnLOverTimeChart from './components/PnLOverTimeChart';
import PnLBySymbolChart from './components/PnLBySymbolChart';
import PnLByOptionTypeChart from './components/PnLByOptionTypeChart';
import PnLByYearMonthChart from './components/PnLByYearMonthChart';
import UnmatchedTradesTable from './components/OptionTypeDistributionChart';

// --- STORAGE KEYS ---
const STORAGE_KEY_TOKEN = 'opt_dashboard_access_token';
const STORAGE_KEY_USER = 'opt_dashboard_user_profile';

// --- HELPERS FOR DATA DEDUPLICATION ---
const getRawTradeKey = (trade: RawTrade): string => {
  const d = new Date(trade.Date);
  const normalizedDate = !isNaN(d.getTime()) ? d.toISOString().split('T')[0] : String(trade.Date).trim();
  const amt = parseFloat(String(trade.Amount).replace(/[$,()]/g, ''));
  const normalizedAmount = isNaN(amt) ? String(trade.Amount).trim() : amt.toFixed(2);

  return [
    normalizedDate,
    String(trade.Action).trim(),
    String(trade.Symbol).trim(),
    String(trade.Account).trim(),
    normalizedAmount,
    String(trade.Quantity).trim()
  ].join('|');
};

const deduplicateRawTrades = (trades: RawTrade[]): RawTrade[] => {
  const seen = new Set<string>();
  const uniqueTrades: RawTrade[] = [];
  for (let i = trades.length - 1; i >= 0; i--) {
    const trade = trades[i];
    const key = getRawTradeKey(trade);
    if (!seen.has(key)) {
      seen.add(key);
      uniqueTrades.unshift(trade);
    }
  }
  return uniqueTrades;
};

// --- AUTOCOMPLETE COMPONENT ---
const AutocompleteInput = ({ value, onChange, options, placeholder, disabled, id }: any) => {
  const [showOptions, setShowOptions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const filteredOptions = useMemo(() =>
    options.filter((option: string) =>
      option.toLowerCase().includes(value.toLowerCase())
    ), [value, options]);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowOptions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  return (
    <div className="relative" ref={wrapperRef}>
      <input
        id={id}
        type="text"
        placeholder={placeholder}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onFocus={() => setShowOptions(true)}
        className="mt-1 block w-full p-2 border border-gray-300 rounded-md shadow-sm focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
        disabled={disabled}
      />
      {showOptions && filteredOptions.length > 0 && (
        <ul className="absolute z-10 w-full bg-white border border-gray-200 rounded-md mt-1 shadow-lg max-h-60 overflow-y-auto">
          {filteredOptions.map((option: string) => (
            <li
              key={option}
              className="px-4 py-2 text-sm text-gray-700 cursor-pointer hover:bg-blue-500 hover:text-white"
              onMouseDown={() => {
                onChange(option);
                setShowOptions(false);
              }}
            >
              {option}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

function App() {
  const [rawCsvData, setRawCsvData] = useState<RawTrade[]>([]);
  const [parsedTrades, setParsedTrades] = useState<ParsedTrade[]>([]);
  const [closedTrades, setClosedTrades] = useState<ClosedTrade[]>([]);
  const [unmatchedTrades, setUnmatchedTrades] = useState<ParsedTrade[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [loadingAction, setLoadingAction] = useState<'parsing' | 'loadingSheet' | 'savingSheet' | null>(null);

  const [isSignedIn, setIsSignedIn] = useState(false);
  const [userProfile, setUserProfile] = useState<{ name: string; email: string; picture: string } | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [saveMessage, setSaveMessage] = useState<string | null>(null);

  const [filterAccount, setFilterAccount] = useState<string>('ALL');
  const [filterStock, setFilterStock] = useState<string>('');
  const [filterOptionType, setFilterOptionType] = useState<OptionType | 'ALL'>('ALL');
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [globalSearchTerm, setGlobalSearchTerm] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<string | null>(null);

  const hasLoadedInitially = useRef(false);

  // Sign out helper to clean state and storage
  const handleSignOut = useCallback(() => {
    if (accessToken) revokeAccessToken(accessToken);
    setIsSignedIn(false);
    setUserProfile(null);
    setAccessToken(null);
    localStorage.removeItem(STORAGE_KEY_TOKEN);
    localStorage.removeItem(STORAGE_KEY_USER);
  }, [accessToken]);

  // Loading function
  const handleLoadFromSheet = useCallback(async (tokenToUse?: string) => {
    const activeToken = tokenToUse || accessToken;
    if (!activeToken) return;

    setIsLoading(true);
    setLoadingAction('loadingSheet');
    setError(null);
    try {
      const data = await fetchRawTradesFromSheet(activeToken);
      if (data && data.length > 0) {
        setRawCsvData(prevData => deduplicateRawTrades([...prevData, ...data]));
      } else {
        // Only set error if it wasn't an automatic silent load
        if (hasLoadedInitially.current) {
           setError("No data found in the Google Sheet.");
        }
      }
    } catch (e: any) {
      console.error("Sheet load error:", e);
      // If unauthorized, session probably expired
      if (e.message.includes('401') || e.message.includes('unauthorized')) {
        handleSignOut();
      } else {
        setError(`Failed to load data from sheet: ${e.message}`);
      }
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
    }
  }, [accessToken, handleSignOut]);

  // Handle successful auth
  const handleTokenResponse = useCallback(async (tokenResponse: any) => {
    if (tokenResponse && tokenResponse.access_token) {
      const token = tokenResponse.access_token;
      setAccessToken(token);
      setIsSignedIn(true);
      localStorage.setItem(STORAGE_KEY_TOKEN, token);
      try {
        const profile = await fetchUserProfile(token);
        setUserProfile(profile);
        localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(profile));
      } catch (e) {
        console.error("Failed to fetch user profile", e);
      }
    }
  }, []);

  // Initialize Google Client and Restore Session
  useEffect(() => {
    initGoogleClient(handleTokenResponse).catch(err => console.error(err));

    const storedToken = localStorage.getItem(STORAGE_KEY_TOKEN);
    const storedUser = localStorage.getItem(STORAGE_KEY_USER);

    if (storedToken && storedUser) {
      setAccessToken(storedToken);
      setIsSignedIn(true);
      setUserProfile(JSON.parse(storedUser));

      // Attempt to verify and auto-load
      fetchUserProfile(storedToken).catch(() => {
        // If verification fails, the token is likely expired
        handleSignOut();
      });
    }
  }, [handleTokenResponse, handleSignOut]);

  // AUTO-LOAD TRIGGER
  useEffect(() => {
    if (isSignedIn && accessToken && !hasLoadedInitially.current) {
      hasLoadedInitially.current = true;
      handleLoadFromSheet(accessToken);
    }
  }, [isSignedIn, accessToken, handleLoadFromSheet]);

  const handleSignIn = () => requestAccessToken();

  const handleDataParsed = (newData: RawTrade[]) => {
    setRawCsvData(prevData => deduplicateRawTrades([...prevData, ...newData]));
    setError(null);
  };

  const handleSaveToSheet = async () => {
    if (!rawCsvData.length || !accessToken) return;
    setIsLoading(true);
    setLoadingAction('savingSheet');
    setSaveMessage('Checking for new data...');
    try {
      const sheetData = await fetchRawTradesFromSheet(accessToken);
      const sheetDataKeys = new Set(sheetData.map(getRawTradeKey));
      const newTrades = rawCsvData.filter(trade => !sheetDataKeys.has(getRawTradeKey(trade)));

      if (newTrades.length === 0) {
        setSaveMessage('No new trades to save.');
        return;
      }

      const result = await saveRawTradesToSheet(newTrades, accessToken);
      if (result.status === 'success') {
        setSaveMessage(`Successfully saved ${newTrades.length} new trades.`);
      } else {
        throw new Error(result.message);
      }
    } catch (e: any) {
      setSaveMessage(`Error: ${e.message}`);
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
      setTimeout(() => setSaveMessage(null), 5000);
    }
  };

  useEffect(() => {
    if (rawCsvData.length > 0) {
      setParsedTrades(parseTrades(rawCsvData));
    } else {
      setParsedTrades([]);
    }
  }, [rawCsvData]);

  useEffect(() => {
    if (parsedTrades.length > 0) {
      const { closedTrades: cTrades, openPositions: oPositions, unmatchedCloses: uCloses } = processClosedTrades(parsedTrades);
      setClosedTrades(cTrades);
      setUnmatchedTrades([...oPositions, ...uCloses].sort((a, b) => a.originalDate.getTime() - b.originalDate.getTime()));
    } else {
      setClosedTrades([]);
      setUnmatchedTrades([]);
    }
  }, [parsedTrades]);

  const availableAccounts = useMemo(() => Array.from(new Set(closedTrades.map(t => t.account))).sort(), [closedTrades]);
  const availableStocks = useMemo(() => Array.from(new Set(closedTrades.map(t => t.stockName))).sort(), [closedTrades]);

  const primaryFilteredTrades = useMemo(() => {
    let currentTrades = closedTrades;
    const lowerCaseGlobalSearch = globalSearchTerm.toLowerCase();

    if (lowerCaseGlobalSearch) {
        currentTrades = currentTrades.filter(trade => 
            Object.values(trade).some(val => String(val).toLowerCase().includes(lowerCaseGlobalSearch))
        );
    }
    if (filterAccount !== 'ALL') currentTrades = currentTrades.filter(t => t.account === filterAccount);
    if (filterStock) currentTrades = currentTrades.filter(t => t.stockName.toLowerCase().includes(filterStock.toLowerCase()));
    if (filterOptionType !== 'ALL') currentTrades = currentTrades.filter(t => t.optionType === filterOptionType);

    const start = filterStartDate ? new Date(filterStartDate) : null;
    const end = filterEndDate ? new Date(filterEndDate) : null;
    if (start || end) {
      currentTrades = currentTrades.filter(trade => {
        const d = new Date(trade.closeDate); d.setHours(0,0,0,0);
        return (!start || d >= start) && (!end || d <= end);
      });
    }
    return currentTrades;
  }, [closedTrades, globalSearchTerm, filterAccount, filterStock, filterOptionType, filterStartDate, filterEndDate]);

  const finalFilteredTradesForTable = useMemo(() => {
    if (!selectedMonth) return primaryFilteredTrades;
    return primaryFilteredTrades.filter(trade => {
        const ym = `${trade.closeDate.getFullYear()}-${(trade.closeDate.getMonth() + 1).toString().padStart(2, '0')}`;
        return ym === selectedMonth;
    });
  }, [primaryFilteredTrades, selectedMonth]);

  const filteredSummary = useMemo(() => calculateSummary(finalFilteredTradesForTable), [finalFilteredTradesForTable]);

  const clearFilters = () => {
    setGlobalSearchTerm(''); setFilterAccount('ALL'); setFilterStock(''); setFilterOptionType('ALL'); setFilterStartDate(''); setFilterEndDate(''); setSelectedMonth(null);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-4 sm:p-6 lg:p-8">
      <header className="bg-white rounded-lg shadow-md p-4 mb-6 flex flex-col sm:flex-row justify-between items-center">
        <h1 className="text-3xl font-extrabold text-gray-800">Option Trading Dashboard</h1>
        <div className="flex items-center space-x-4">
          {isSignedIn && userProfile ? (
            <div className="flex items-center space-x-3">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-bold text-gray-800">{userProfile.name}</p>
                <p className="text-xs text-gray-500">{userProfile.email}</p>
              </div>
              <img src={userProfile.picture} alt="avatar" className="w-10 h-10 rounded-full border-2 border-indigo-200" />
              <button onClick={handleSignOut} className="px-3 py-1 bg-gray-100 text-gray-600 rounded text-sm hover:bg-gray-200 transition-colors">Sign Out</button>
            </div>
          ) : (
            <button onClick={handleSignIn} className="flex items-center px-4 py-2 bg-white border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none transition-all">
              <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" className="w-5 h-5 mr-2" alt="Google" />
              Sign in with Google
            </button>
          )}
        </div>
      </header>

      <section className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        <FileUpload 
          onDataParsed={handleDataParsed}
          isLoading={isLoading && loadingAction === 'parsing'}
          setIsLoading={(val) => { setIsLoading(val); if(val) setLoadingAction('parsing'); else setLoadingAction(null); }}
          setError={setError}
        />
        <div className="bg-white p-6 rounded-lg shadow-md flex flex-col justify-center items-center text-center relative overflow-hidden">
          <div className="absolute top-0 right-0 p-2">
            {isLoading && loadingAction === 'loadingSheet' && (
              <div className="flex space-x-1">
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
              </div>
            )}
          </div>
          <h3 className="text-lg font-semibold mb-2 text-gray-800">Google Sheets Sync</h3>
          <p className="text-sm text-gray-500 mb-4">Data is automatically loaded on login</p>
          <button 
            onClick={() => handleLoadFromSheet()} 
            disabled={!isSignedIn || isLoading}
            className="px-6 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700 disabled:bg-gray-400 shadow-md transition-all active:transform active:scale-95"
          >
            {loadingAction === 'loadingSheet' ? 'Refreshing...' : 'Refresh Data'}
          </button>
          {isSignedIn && <button onClick={handleSaveToSheet} disabled={isLoading || !rawCsvData.length} className="mt-4 text-sm text-green-600 hover:underline font-medium">Save current session to sheet</button>}
          {saveMessage && <p className="mt-2 text-xs text-indigo-600 font-bold bg-indigo-50 px-2 py-1 rounded">{saveMessage}</p>}
        </div>
      </section>

      {error && (
        <div className="bg-red-50 border-l-4 border-red-400 p-4 rounded mb-6 flex items-center justify-between shadow-sm">
          <div className="flex items-center">
            <svg className="h-5 w-5 text-red-400 mr-2" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
            </svg>
            <p className="text-sm text-red-700 font-medium">{error}</p>
          </div>
          <button onClick={() => setError(null)} className="text-red-400 hover:text-red-500">
            <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>
      )}

      {(rawCsvData.length > 0 || isLoading) ? (
        <>
          <section className="bg-white p-6 rounded-lg shadow-md mb-8 border border-gray-100">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div><label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Global Search</label><input type="text" className="w-full p-2 border border-gray-200 rounded focus:ring-2 focus:ring-indigo-500 outline-none" value={globalSearchTerm} onChange={e => setGlobalSearchTerm(e.target.value)} placeholder="Symbol, P&L, etc..." /></div>
              <div><label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Account</label><select className="w-full p-2 border border-gray-200 rounded focus:ring-2 focus:ring-indigo-500 outline-none" value={filterAccount} onChange={e => setFilterAccount(e.target.value)}><option value="ALL">All Accounts</option>{availableAccounts.map(a => <option key={a} value={a}>{a}</option>)}</select></div>
              <div><label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Stock</label><AutocompleteInput value={filterStock} onChange={setFilterStock} options={availableStocks} placeholder="Stock Symbol" id="stock-filter" /></div>
              <div><label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">Type</label><select className="w-full p-2 border border-gray-200 rounded focus:ring-2 focus:ring-indigo-500 outline-none" value={filterOptionType} onChange={e => setFilterOptionType(e.target.value as any)}><option value="ALL">All Types</option><option value={OptionType.CALL}>Call</option><option value={OptionType.PUT}>Put</option></select></div>
              <div className="flex items-end"><button onClick={clearFilters} className="w-full py-2 bg-gray-50 text-gray-600 rounded hover:bg-gray-100 border border-gray-200 transition-colors">Clear All Filters</button></div>
            </div>
          </section>

          <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            <SummaryCard title="Total P&L" value={`$${filteredSummary.totalPnL.toLocaleString()}`} valueColorClass={filteredSummary.totalPnL >= 0 ? 'text-emerald-600' : 'text-rose-600'} />
            <SummaryCard title="Win Rate" value={`${((filteredSummary.winningTrades / (filteredSummary.totalTrades || 1)) * 100).toFixed(1)}%`} valueColorClass="text-emerald-600" />
            <SummaryCard title="Total Trades" value={filteredSummary.totalTrades} />
            <SummaryCard title="Avg P&L / Trade" value={`$${filteredSummary.averagePnLPerTrade.toFixed(2)}`} valueColorClass={filteredSummary.averagePnLPerTrade >= 0 ? 'text-emerald-600' : 'text-rose-600'} />
          </section>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            <PnLOverTimeChart trades={primaryFilteredTrades} />
            <PnLByYearMonthChart trades={primaryFilteredTrades} onMonthClick={m => setSelectedMonth(m === selectedMonth ? null : m)} selectedMonth={selectedMonth} />
          </div>

          <div className="mb-8">
            <TradeTable trades={finalFilteredTradesForTable} />
          </div>

          {unmatchedTrades.length > 0 && (
            <div className="mt-8 bg-white p-6 rounded-lg shadow-md border border-gray-100">
              <h2 className="text-xl font-bold mb-4 text-gray-800">Open & Unmatched Positions</h2>
              <UnmatchedTradesTable trades={unmatchedTrades} />
            </div>
          )}
        </>
      ) : (
        <div className="flex flex-col items-center justify-center p-16 bg-white rounded-lg shadow-md border-2 border-dashed border-gray-200">
          <div className="p-4 bg-indigo-50 rounded-full mb-4">
            <svg className="w-12 h-12 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
          </div>
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Ready to Analyze?</h2>
          <p className="text-gray-500 mb-6 max-w-md text-center">Login with Google to automatically fetch your trades from Sheets, or upload a CSV file manually to start your dashboard.</p>
          {!isSignedIn && (
             <button onClick={handleSignIn} className="px-8 py-3 bg-indigo-600 text-white rounded-lg shadow-lg hover:bg-indigo-700 transition-all font-semibold flex items-center">
                <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" className="w-5 h-5 mr-3 filter brightness-200" alt="G" />
                Get Started with Google
             </button>
          )}
        </div>
      )}
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { ClosedTrade, OptionType } from '../types';

interface TradeTableProps {
  trades: ClosedTrade[];
}

interface SortConfig {
  key: string; // Changed to string to allow dot notation for nested properties
  direction: 'ascending' | 'descending';
}

const getNestedValue = (obj: any, path: string) => {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined) return undefined;
    current = current[part];
  }
  return current;
};

const formatToMMDDYYYY = (date: Date) => {
  const m = (date.getMonth() + 1).toString().padStart(2, '0');
  const d = date.getDate().toString().padStart(2, '0');
  const y = date.getFullYear();
  return `${m}/${d}/${y}`;
};

const TradeTable: React.FC<TradeTableProps> = ({ trades }) => {
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'closeDate', direction: 'descending' });

  const sortedTrades = useMemo(() => {
    const sortableTrades = [...trades];
    if (sortConfig.key) {
      sortableTrades.sort((a, b) => {
        const aValue = getNestedValue(a, sortConfig.key);
        const bValue = getNestedValue(b, sortConfig.key);

        if (aValue === undefined || bValue === undefined) return 0;

        let comparison = 0;
        if (typeof aValue === 'string' && typeof bValue === 'string') {
          comparison = aValue.localeCompare(bValue);
        } else if (aValue instanceof Date && bValue instanceof Date) {
          comparison = aValue.getTime() - bValue.getTime();
        } else {
          comparison = (aValue || 0) < (bValue || 0) ? -1 : (aValue || 0) > (bValue || 0) ? 1 : 0;
        }

        return sortConfig.direction === 'ascending' ? comparison : -comparison;
      });
    }
    return sortableTrades;
  }, [trades, sortConfig]);

  const requestSort = (key: string) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const getSortIndicator = (key: string) => {
    if (sortConfig.key === key) {
      return sortConfig.direction === 'ascending' ? ' ▲' : ' ▼';
    }
    return '';
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(amount);
  };

  const formatOptionType = (type: OptionType) => {
    return type === OptionType.CALL ? 'Call' : 'Put';
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow overflow-x-auto border border-gray-100">
      <h2 className="text-xl font-bold text-gray-800 mb-4">Closed Trades Details</h2>
      {trades.length === 0 ? (
        <p className="text-gray-600 text-center py-10">No closed trades found for the selected filters.</p>
      ) : (
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('closeDate')}>Close Date {getSortIndicator('closeDate')}</th>
