import React, { useState, useMemo } from 'react';
import { ParsedTrade, OptionType } from '../types';

interface UnmatchedTradesTableProps {
  trades: ParsedTrade[];
}

interface SortConfig {
  key: keyof ParsedTrade;
  direction: 'ascending' | 'descending';
}

const formatToMMDDYYYY = (date: Date) => {
  const m = (date.getMonth() + 1).toString().padStart(2, '0');
  const d = date.getDate().toString().padStart(2, '0');
  const y = date.getFullYear();
  return `${m}/${d}/${y}`;
};

const UnmatchedTradesTable: React.FC<UnmatchedTradesTableProps> = ({ trades }) => {
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'originalDate', direction: 'descending' });

  const sortedTrades = useMemo(() => {
    const sortableTrades = [...trades];
    if (sortConfig.key) {
      sortableTrades.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        if (aValue === undefined || bValue === undefined) return 0;

        let comparison = 0;
        if (typeof aValue === 'string' && typeof bValue === 'string') {
          comparison = aValue.localeCompare(bValue);
        } else if (aValue instanceof Date && bValue instanceof Date) {
          comparison = aValue.getTime() - bValue.getTime();
        } else {
          comparison = (aValue as number || 0) < (bValue as number || 0) ? -1 : (aValue as number || 0) > (bValue as number || 0) ? 1 : 0;
        }

        return sortConfig.direction === 'ascending' ? comparison : -comparison;
      });
    }
    return sortableTrades;
  }, [trades, sortConfig]);

  const requestSort = (key: keyof ParsedTrade) => {
    let direction: 'ascending' | 'descending' = 'ascending';
    if (sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const getSortIndicator = (key: keyof ParsedTrade) => {
    if (sortConfig.key === key) {
      return sortConfig.direction === 'ascending' ? ' ▲' : ' ▼';
    }
    return '';
  };

  const formatCurrency = (amount: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount);
  const formatOptionType = (type: OptionType) => (type === OptionType.CALL ? 'Call' : 'Put');

  return (
    <div className="overflow-x-auto">
      {trades.length === 0 ? (
        <p className="text-gray-600 text-center py-10">No unmatched trades or open positions found.</p>
      ) : (
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('originalDate')}>Date {getSortIndicator('originalDate')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('action')}>Action {getSortIndicator('action')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('stockName')}>Stock {getSortIndicator('stockName')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('optionDate')}>Expiry {getSortIndicator('optionDate')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('strikePrice')}>Strike {getSortIndicator('strikePrice')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('optionType')}>Type {getSortIndicator('optionType')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('quantity')}>Quantity {getSortIndicator('quantity')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('tradePrice')}>Price {getSortIndicator('tradePrice')}</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider cursor-pointer" onClick={() => requestSort('amount')}>Amount {getSortIndicator('amount')}</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {sortedTrades.map((trade) => (
              <tr key={trade.id} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">{formatToMMDDYYYY(trade.originalDate)}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{trade.action}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-bold">{trade.stockName}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{formatToMMDDYYYY(trade.optionDate)}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{formatCurrency(trade.strikePrice)}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{formatOptionType(trade.optionType)}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{trade.quantity}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{formatCurrency(trade.tradePrice)}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">{formatCurrency(trade.amount)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

