import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ClosedTrade } from '../types';

interface PnLByYearMonthChartProps {
  trades: ClosedTrade[];
  baseFund: number;
  onMonthClick: (yearMonth: string | null) => void;
  selectedMonth: string | null;
}

interface ChartData {
  yearMonth: string; // e.g., "2025-10"
  formattedMonth: string; // e.g., "Oct 2025"
  monthlyPnL: number;
  monthlyPercent: number;
  cumulativePnL: number;
  cumulativePercent: number;
}

const PnLByYearMonthChart: React.FC<PnLByYearMonthChartProps> = ({ trades, baseFund, onMonthClick, selectedMonth }) => {
  const chartData: ChartData[] = React.useMemo(() => {
    // Sort trades by close date to ensure correct chronological aggregation
    const sortedTrades = [...trades].sort((a, b) => a.closeDate.getTime() - b.closeDate.getTime());

    const pnlByYearMonth: { [key: string]: number } = {}; // { "YYYY-MM": monthlyPnL }

    for (const trade of sortedTrades) {
      const year = trade.closeDate.getUTCFullYear();
      const month = (trade.closeDate.getUTCMonth() + 1).toString().padStart(2, '0');
      const yearMonthKey = `${year}-${month}`; // "YYYY-MM"
      pnlByYearMonth[yearMonthKey] = (pnlByYearMonth[yearMonthKey] || 0) + trade.pnl;
    }

    const data: ChartData[] = [];
    let cumulativePnL = 0;

    const sortedYearMonths = Object.keys(pnlByYearMonth).sort();
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

    for (const ymKey of sortedYearMonths) {
      const monthlyPnL = pnlByYearMonth[ymKey];
      cumulativePnL += monthlyPnL;

      const [y, m] = ymKey.split('-').map(Number);
      const label = `${monthNames[m-1]} ${y}`;

      data.push({
        yearMonth: ymKey,
        formattedMonth: label,
        monthlyPnL: monthlyPnL,
        monthlyPercent: baseFund > 0 ? (monthlyPnL / baseFund) * 100 : 0,
        cumulativePnL: cumulativePnL,
        cumulativePercent: baseFund > 0 ? (cumulativePnL / baseFund) * 100 : 0,
      });
    }

    return data;
  }, [trades, baseFund]);

  if (trades.length === 0 || chartData.length === 0) {
    return (
      <div className="bg-white p-6 rounded-lg shadow flex items-center justify-center h-full">
        <p className="text-gray-600">No data to display Monthly P&L by Year & Month.</p>
      </div>
    );
  }

  const currencyFormatter = (value: number) => `$${value.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div className="bg-white p-3 border border-gray-100 rounded-xl shadow-lg text-xs font-medium">
          <p className="font-black text-slate-800 mb-2 border-b border-slate-50 pb-1">{label}</p>
          <div className="space-y-1.5">
            <p className="flex justify-between space-x-6">
              <span className="text-slate-500">Monthly P&L:</span> 
              <span className={data.monthlyPnL >= 0 ? 'text-emerald-600 font-bold' : 'text-rose-600 font-bold'}>{currencyFormatter(data.monthlyPnL)}</span>
            </p>
            <p className="flex justify-between space-x-6">
              <span className="text-slate-500">Monthly %:</span> 
              <span className={data.monthlyPercent >= 0 ? 'text-emerald-600 font-bold' : 'text-rose-600 font-bold'}>{data.monthlyPercent.toFixed(2)}%</span>
            </p>
            <div className="h-[1px] bg-slate-50 my-1"></div>
            <p className="flex justify-between space-x-6">
              <span className="text-slate-500">Portfolio Total:</span> 
              <span className={data.cumulativePnL >= 0 ? 'text-emerald-600 font-bold' : 'text-rose-600 font-bold'}>{currencyFormatter(data.cumulativePnL)}</span>
            </p>
            <p className="flex justify-between space-x-6">
              <span className="text-slate-500">Total ROI %:</span> 
              <span className={data.cumulativePercent >= 0 ? 'text-emerald-600 font-bold' : 'text-rose-600 font-bold'}>{data.cumulativePercent.toFixed(2)}%</span>
            </p>
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
      <h2 className="text-xl font-black text-slate-800 mb-4 uppercase tracking-tight">Monthly Performance</h2>
      <ResponsiveContainer width="100%" height={300}>
        <BarChart 
          data={chartData} 
          margin={{ top: 5, right: 20, left: 10, bottom: 5 }}
        >
          <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" vertical={false} />
          <XAxis dataKey="formattedMonth" tick={{fontSize: 10}} interval="preserveStartEnd" minTickGap={30} stroke="#94a3b8" />
          <YAxis tick={{fontSize: 10}} tickFormatter={(value) => currencyFormatter(value)} stroke="#94a3b8" />
          <Tooltip content={<CustomTooltip />} cursor={{fill: '#f8fafc'}} />
          <Bar dataKey="monthlyPnL" onClick={(data) => onMonthClick(data.yearMonth)}>
            {chartData.map((entry, index) => {
              const isSelected = selectedMonth === entry.yearMonth;
              const defaultColor = entry.monthlyPnL >= 0 ? '#10b981' : '#f43f5e';
              const opacity = selectedMonth && !isSelected ? 0.3 : 1;

              return (
                <Cell 
                  key={`cell-${index}`} 
                  fill={defaultColor}
                  cursor="pointer"
                  style={{ opacity: opacity, transition: 'opacity 0.2s' }}
                />
              );
            })}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

