  const [globalSearchTerm, setGlobalSearchTerm] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<string | null>(null);

  const hasLoadedInitially = useRef(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_BASE_FUND, baseFund.toString());
  }, [baseFund]);

  const handleSignOut = useCallback(() => {
    if (accessToken) revokeAccessToken(accessToken);
    setIsSignedIn(false);
    setUserProfile(null);
    setAccessToken(null);
    localStorage.removeItem(STORAGE_KEY_TOKEN);
    localStorage.removeItem(STORAGE_KEY_USER);
  }, [accessToken]);

  const handleLoadFromSheet = useCallback(async (tokenToUse?: string) => {
    const activeToken = tokenToUse || accessToken;
    if (!activeToken) return;

    setIsLoading(true);
    setLoadingAction('loadingSheet');
    setError(null);
    try {
      const data = await fetchRawTradesFromSheet(activeToken);
      if (data && data.length > 0) {
        setRawCsvData(data);
      }
    } catch (e: any) {
      if (e.message.includes('401') || e.message.includes('unauthorized')) {
        handleSignOut();
      } else {
        setError(`Failed to load data from sheet: ${e.message}`);
      }
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
    }
  }, [accessToken, handleSignOut]);

  const handleTokenResponse = useCallback(async (tokenResponse: any) => {
    if (tokenResponse && tokenResponse.access_token) {
      const token = tokenResponse.access_token;
      setAccessToken(token);
      setIsSignedIn(true);
      localStorage.setItem(STORAGE_KEY_TOKEN, token);
      try {
        const profile = await fetchUserProfile(token);
        setUserProfile(profile);
        localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(profile));
      } catch (e) {
        console.error("Failed to fetch user profile", e);
      }
    }
  }, []);

  useEffect(() => {
    initGoogleClient(handleTokenResponse).catch(err => console.error(err));
    const storedToken = localStorage.getItem(STORAGE_KEY_TOKEN);
    const storedUser = localStorage.getItem(STORAGE_KEY_USER);
    if (storedToken && storedUser) {
      setAccessToken(storedToken);
      setIsSignedIn(true);
      setUserProfile(JSON.parse(storedUser));
      fetchUserProfile(storedToken).catch(() => handleSignOut());
    }
  }, [handleTokenResponse, handleSignOut]);

  useEffect(() => {
    if (isSignedIn && accessToken && !hasLoadedInitially.current) {
      hasLoadedInitially.current = true;
      handleLoadFromSheet(accessToken);
    }
  }, [isSignedIn, accessToken, handleLoadFromSheet]);

  const handleSignIn = () => requestAccessToken();

  const handleDataParsed = (newData: RawTrade[]) => {
    setRawCsvData(prevData => [...prevData, ...newData]);
    setError(null);
  };

  const handleSaveToSheet = async () => {
    if (!rawCsvData.length || !accessToken) return;
    setIsLoading(true);
    setLoadingAction('savingSheet');
    setSaveMessage('Checking for new data...');
    try {
      const sheetData = await fetchRawTradesFromSheet(accessToken);
      const sheetCounts: Record<string, number> = {};
      sheetData.forEach(t => {
        const k = getRawTradeKey(t);
        sheetCounts[k] = (sheetCounts[k] || 0) + 1;
      });
      const localCounts: Record<string, number> = {};
      const newTrades: RawTrade[] = [];
      rawCsvData.forEach(trade => {
        const key = getRawTradeKey(trade);
        localCounts[key] = (localCounts[key] || 0) + 1;
        if (localCounts[key] > (sheetCounts[key] || 0)) {
          newTrades.push(trade);
        }
      });
      if (newTrades.length === 0) {
        setSaveMessage('No new trades to save.');
        return;
      }
      const result = await saveRawTradesToSheet(newTrades, accessToken);
      if (result.status === 'success') {
        setSaveMessage(`Successfully saved ${newTrades.length} new trades.`);
      } else {
        throw new Error(result.message);
      }
    } catch (e: any) {
      setSaveMessage(`Error: ${e.message}`);
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
      setTimeout(() => setSaveMessage(null), 5000);
    }
  };

  useEffect(() => {
    if (rawCsvData.length > 0) {
      setParsedTrades(parseTrades(rawCsvData));
    } else {
      setParsedTrades([]);
    }
  }, [rawCsvData]);

  useEffect(() => {
    if (parsedTrades.length > 0) {
      const { closedTrades: cTrades, openPositions: oPositions, unmatchedCloses: uCloses } = processClosedTrades(parsedTrades);
      setClosedTrades(cTrades);
      setUnmatchedTrades([...oPositions, ...uCloses].sort((a, b) => a.originalDate.getTime() - b.originalDate.getTime()));
    } else {
      setClosedTrades([]);
      setUnmatchedTrades([]);
    }
  }, [parsedTrades]);

  // Date Preset logic
  useEffect(() => {
    const today = new Date();
    today.setUTCHours(0, 0, 0, 0);

    let start = '';
    let end = '';

    switch (selectedDatePreset) {
      case 'current_month':
        const sm = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), 1));
        const em = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + 1, 0));
        start = formatDateToISO(sm);
        end = formatDateToISO(em);
        break;
      case 'current_year':
        const sy = new Date(Date.UTC(today.getUTCFullYear(), 0, 1));
        const ey = new Date(Date.UTC(today.getUTCFullYear(), 11, 31));
        start = formatDateToISO(sy);
        end = formatDateToISO(ey);
        break;
      case 'last_year':
        const sly = new Date(Date.UTC(today.getUTCFullYear() - 1, 0, 1));
        const ely = new Date(Date.UTC(today.getUTCFullYear() - 1, 11, 31));
        start = formatDateToISO(sly);
        end = formatDateToISO(ely);
        break;
      case 'all':
        start = '';
        end = '';
        break;
      default:
        return;
    }
    setFilterStartDate(start);
    setFilterEndDate(end);
  }, [selectedDatePreset]);

  const availableAccounts = useMemo(() => Array.from(new Set(rawCsvData.map(t => t.Account))).sort(), [rawCsvData]);
  const availableStocks = useMemo(() => Array.from(new Set(closedTrades.map(t => t.stockName))).sort(), [closedTrades]);

  const primaryFilteredTrades = useMemo(() => {
    let currentTrades = closedTrades;
    const lowerCaseGlobalSearch = globalSearchTerm.toLowerCase();

    if (lowerCaseGlobalSearch) {
        currentTrades = currentTrades.filter(trade => 
            Object.values(trade).some(val => String(val).toLowerCase().includes(lowerCaseGlobalSearch))
        );
    }
    if (filterAccount !== 'ALL') currentTrades = currentTrades.filter(t => t.account === filterAccount);
    if (filterStock) currentTrades = currentTrades.filter(t => t.stockName.toLowerCase().includes(filterStock.toLowerCase()));
    if (filterOptionType !== 'ALL') currentTrades = currentTrades.filter(t => t.optionType === filterOptionType);

    const startStr = filterStartDate;
    const endStr = filterEndDate;

    if (startStr || endStr) {
      currentTrades = currentTrades.filter(trade => {
        const d = new Date(trade.closeDate);
        d.setUTCHours(0, 0, 0, 0);
        const tradeTime = d.getTime();

        const matchesStart = !startStr || tradeTime >= new Date(startStr).getTime();
        const matchesEnd = !endStr || tradeTime <= new Date(endStr).getTime();
        return matchesStart && matchesEnd;
      });
    }
    return currentTrades;
  }, [closedTrades, globalSearchTerm, filterAccount, filterStock, filterOptionType, filterStartDate, filterEndDate]);

  const finalFilteredTradesForTable = useMemo(() => {
    if (!selectedMonth) return primaryFilteredTrades;
    return primaryFilteredTrades.filter(trade => {
        const ym = `${trade.closeDate.getUTCFullYear()}-${(trade.closeDate.getUTCMonth() + 1).toString().padStart(2, '0')}`;
        return ym === selectedMonth;
    });
  }, [primaryFilteredTrades, selectedMonth]);

  const filteredSummary = useMemo(() => calculateSummary(finalFilteredTradesForTable), [finalFilteredTradesForTable]);

  const filteredUnmatchedTrades = useMemo(() => {
    if (filterAccount === 'ALL') return unmatchedTrades;
    return unmatchedTrades.filter(t => t.account === filterAccount);
  }, [unmatchedTrades, filterAccount]);

  const portfolioReturnPercent = useMemo(() => {
    if (!baseFund || baseFund === 0) return 0;
    return (filteredSummary.totalPnL / baseFund) * 100;
  }, [filteredSummary.totalPnL, baseFund]);

  const clearFilters = () => {
    setGlobalSearchTerm(''); 
    setFilterAccount('ALL'); 
    setFilterStock(''); 
    setFilterOptionType('ALL'); 
    setFilterStartDate(''); 
    setFilterEndDate(''); 
    setSelectedMonth(null);
    setSelectedDatePreset('all');
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-indigo-50 p-4 sm:p-6 lg:p-8">
      <header className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 mb-6 flex flex-col sm:flex-row justify-between items-center transition-all duration-300">
        <div className="flex items-center">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center mr-3 shadow-indigo-200 shadow-lg">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg>
          </div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Option Intelligence</h1>
        </div>
        <div className="flex items-center space-x-4">
          {isSignedIn && userProfile ? (
            <div className="flex items-center space-x-3 bg-slate-50 px-4 py-1.5 rounded-full border border-slate-100 shadow-sm">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-slate-800 leading-tight">{userProfile.name}</p>
                <p className="text-[10px] text-indigo-500 font-bold">{userProfile.email}</p>
              </div>
              <img src={userProfile.picture} alt="avatar" className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
              <button onClick={handleSignOut} className="text-[10px] font-black text-slate-400 hover:text-indigo-600 uppercase tracking-widest transition-colors ml-1">Logout</button>
            </div>
          ) : (
            <button onClick={handleSignIn} className="flex items-center px-4 py-2 bg-white border border-slate-200 rounded-full shadow-sm text-xs font-black text-slate-700 hover:bg-slate-50 hover:border-indigo-300 transition-all uppercase tracking-wider">
              <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" className="w-4 h-4 mr-2" alt="Google" />
              Sign in
            </button>
          )}
        </div>
      </header>

      <section className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        <FileUpload 
          onDataParsed={handleDataParsed}
          isLoading={isLoading && loadingAction === 'parsing'}
          setIsLoading={(val) => { setIsLoading(val); if(val) setLoadingAction('parsing'); else setLoadingAction(null); }}
          setError={setError}
          existingAccounts={availableAccounts}
        />
        <div className="bg-white p-6 rounded-2xl shadow-sm flex flex-col justify-center items-center text-center relative overflow-hidden border border-slate-200">
          <div className="absolute top-0 right-0 p-3">
            {isLoading && loadingAction === 'loadingSheet' && (
              <div className="flex space-x-1">
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            )}
          </div>
          <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center mb-4 text-indigo-600 shadow-inner">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"></path></svg>
          </div>
          <h3 className="text-lg font-black mb-1 text-slate-800 uppercase tracking-tight">Cloud Warehouse</h3>
          <p className="text-xs text-slate-500 mb-5 font-medium">Sync trades with your centralized Google Sheet</p>
          <div className="flex space-x-3 w-full max-w-xs">
            <button 
              onClick={() => handleLoadFromSheet()} 
              disabled={!isSignedIn || isLoading}
              className="flex-1 px-4 py-2.5 bg-indigo-600 text-white text-xs font-black rounded-xl hover:bg-indigo-700 disabled:bg-slate-200 disabled:text-slate-400 shadow-md transition-all active:transform active:scale-95 uppercase tracking-wider"
            >
              {loadingAction === 'loadingSheet' ? 'Syncing...' : 'Fetch All'}
            </button>
            <button 
              onClick={handleSaveToSheet} 
              disabled={isLoading || !rawCsvData.length || !isSignedIn} 
              className="flex-1 px-4 py-2.5 bg-white text-indigo-600 border-2 border-indigo-600 text-xs font-black rounded-xl hover:bg-indigo-50 disabled:border-slate-100 disabled:text-slate-300 transition-all shadow-sm uppercase tracking-wider"
            >
              Push New
            </button>
          </div>
          {saveMessage && <p className="mt-3 text-[10px] font-black text-indigo-700 bg-indigo-50 px-3 py-1 rounded-full animate-pulse uppercase tracking-wider">{saveMessage}</p>}
        </div>
      </section>

      {error && (
        <div className="bg-rose-50 border-l-4 border-rose-500 p-4 rounded-r-2xl mb-6 flex items-center justify-between shadow-sm animate-in slide-in-from-top duration-300">
          <div className="flex items-center">
            <svg className="h-6 w-6 text-rose-500 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
            <p className="text-sm text-rose-800 font-bold">{error}</p>
          </div>
          <button onClick={() => setError(null)} className="text-rose-400 hover:text-rose-600 transition-colors">
            <svg className="h-5 w-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>
      )}

      {(rawCsvData.length > 0 || isLoading) ? (
        <>
          <section className="bg-white p-6 rounded-2xl shadow-sm mb-8 border border-slate-200 overflow-visible">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-8 gap-4">
              <div className="lg:col-span-1 bg-indigo-50/50 p-2 rounded-xl border border-indigo-100">
                <label className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1.5 block">Base Fund ($)</label>
                <input 
                  type="number" 
                  className="w-full px-2 py-1.5 bg-white border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs font-bold text-indigo-700 transition-all" 
                  value={baseFund} 
                  onChange={e => setBaseFund(Math.max(0, parseFloat(e.target.value) || 0))} 
                  placeholder="Initial Capital"
                />
              </div>
              <div className="relative group lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Search</label>
                <div className="relative">
                  <input type="text" className="w-full pl-9 pr-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs" value={globalSearchTerm} onChange={e => setGlobalSearchTerm(e.target.value)} placeholder="Symbol, P&L..." />
                  <svg className="w-3.5 h-3.5 text-gray-400 absolute left-3 top-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                </div>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Account</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={filterAccount} onChange={e => setFilterAccount(e.target.value)}>
                  <option value="ALL">All Accounts</option>
                  {availableAccounts.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>
              <div className="lg:col-span-1">
                <AutocompleteInput 
                  label="Symbol"
                  value={filterStock} 
                  onChange={setFilterStock} 
                  options={availableStocks} 
                  placeholder="Stock" 
                  id="stock-filter" 
                />
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Option Type</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={filterOptionType} onChange={e => setFilterOptionType(e.target.value as any)}>
                  <option value="ALL">All Types</option>
                  <option value={OptionType.CALL}>Calls</option>
                  <option value={OptionType.PUT}>Puts</option>
                </select>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Quick Filter</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={selectedDatePreset} onChange={e => setSelectedDatePreset(e.target.value as any)}>
                  <option value="all">All Time</option>
                  <option value="current_month">Current Month</option>
                  <option value="current_year">Current Year</option>
                  <option value="last_year">Last Year</option>
                  <option value="custom">Custom Range</option>
                </select>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Start - End</label>
                <div className="flex space-x-2">
                  <input type="date" className="w-1/2 p-2 bg-gray-50 border border-gray-200 rounded-lg text-[10px] focus:ring-2 focus:ring-indigo-500 outline-none" value={filterStartDate} onChange={e => {setFilterStartDate(e.target.value); setSelectedDatePreset('custom');}} />
                  <input type="date" className="w-1/2 p-2 bg-gray-50 border border-gray-200 rounded-lg text-[10px] focus:ring-2 focus:ring-indigo-500 outline-none" value={filterEndDate} onChange={e => {setFilterEndDate(e.target.value); setSelectedDatePreset('custom');}} />
                </div>
              </div>
              <div className="flex items-end lg:col-span-1">
                <button onClick={clearFilters} className="w-full py-2.5 bg-slate-100 text-slate-700 text-xs font-black rounded-lg hover:bg-slate-800 hover:text-white transition-all active:scale-95 shadow-sm uppercase tracking-widest">Clear</button>
              </div>
            </div>
          </section>

          <section className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
            <SummaryCard title="Total Net P&L" value={`$${filteredSummary.totalPnL.toLocaleString()}`} valueColorClass={filteredSummary.totalPnL >= 0 ? 'text-emerald-600' : 'text-rose-600'} />
            <SummaryCard title="Portfolio Return %" value={`${portfolioReturnPercent.toFixed(2)}%`} valueColorClass={portfolioReturnPercent >= 0 ? 'text-emerald-600' : 'text-rose-600'} description={`Based on $${baseFund.toLocaleString()} fund`} />
            <SummaryCard title="Win Rate" value={`${((filteredSummary.winningTrades / (filteredSummary.totalTrades || 1)) * 100).toFixed(1)}%`} valueColorClass="text-emerald-600" />
            <SummaryCard title="Closed Trades" value={filteredSummary.totalTrades} />
            <SummaryCard title="Avg / Trade" value={`$${filteredSummary.averagePnLPerTrade.toFixed(2)}`} valueColorClass={filteredSummary.averagePnLPerTrade >= 0 ? 'text-emerald-600' : 'text-rose-600'} />
          </section>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
            <PnLOverTimeChart trades={primaryFilteredTrades} baseFund={baseFund} />
            <PnLByYearMonthChart trades={primaryFilteredTrades} baseFund={baseFund} onMonthClick={m => setSelectedMonth(m === selectedMonth ? null : m)} selectedMonth={selectedMonth} />
          </div>

          <div className="mb-8">
            <TradeTable trades={finalFilteredTradesForTable} />
          </div>

          {filteredUnmatchedTrades.length > 0 && (
            <div className="mt-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <h2 className="text-xl font-black text-slate-800 mb-5 uppercase tracking-tight">Active & Unmatched</h2>
              <UnmatchedTradesTable trades={filteredUnmatchedTrades} />
            </div>
          )}
        </>
      ) : (
        <div className="flex flex-col items-center justify-center p-20 bg-white rounded-3xl shadow-sm border-2 border-dashed border-slate-200 transition-all hover:border-indigo-100">
          <div className="p-6 bg-indigo-50 rounded-2xl mb-6 ring-8 ring-indigo-50/30">
            <svg className="w-16 h-16 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
          </div>
          <h2 className="text-3xl font-black text-slate-800 mb-3 tracking-tight uppercase">Trading Intelligence</h2>
          <p className="text-slate-500 mb-8 max-w-lg text-center font-medium leading-relaxed">Connect to Google to sync your trades or upload a CSV file manually. Date format: <span className="text-indigo-600 font-black">MM/DD/YYYY</span></p>
          {!isSignedIn && (
             <button onClick={handleSignIn} className="px-10 py-4 bg-indigo-600 text-white rounded-2xl shadow-lg hover:bg-indigo-700 transition-all font-black text-sm uppercase tracking-widest flex items-center group">
                <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" className="w-5 h-5 mr-4 filter brightness-200 group-hover:scale-110 transition-transform" alt="G" />
                Connect Google Account
             </button>
          )}
        </div>
      )}
      <footer className="mt-12 text-center text-slate-300 text-[10px] font-black uppercase tracking-[0.5em]">
        MM/DD/YYYY Compliant • Financial Dashboard v2.3.2
      </footer>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { RawTrade, ParsedTrade, ClosedTrade, SummaryData, OptionType } from './types';
import { parseTrades, processClosedTrades, calculateSummary } from './services/csvParser';
import { initGoogleClient, requestAccessToken, revokeAccessToken, fetchUserProfile, saveRawTradesToSheet, fetchRawTradesFromSheet } from './services/google';
import FileUpload from './components/FileUpload';
import SummaryCard from './components/SummaryCard';
import TradeTable from './components/TradeTable';
import PnLOverTimeChart from './components/PnLOverTimeChart';
import PnLBySymbolChart from './components/PnLBySymbolChart';
import PnLByOptionTypeChart from './components/PnLByOptionTypeChart';
import PnLByYearMonthChart from './components/PnLByYearMonthChart';
import UnmatchedTradesTable from './components/OptionTypeDistributionChart';

// --- STORAGE KEYS ---
const STORAGE_KEY_TOKEN = 'opt_dashboard_access_token';
const STORAGE_KEY_USER = 'opt_dashboard_user_profile';
const STORAGE_KEY_BASE_FUND = 'opt_dashboard_base_fund';
const STORAGE_KEY_LAST_IMPORT = 'opt_dashboard_last_import';

// Helper for input type="date" (YYYY-MM-DD)
const formatDateToISO = (date: Date): string => {
  const year = date.getUTCFullYear();
  const month = (date.getUTCMonth() + 1).toString().padStart(2, '0');
  const day = date.getUTCDate().toString().padStart(2, '0');
  return `${year}-${month}-${day}`;
};

// --- HELPERS FOR DATA DEDUPLICATION (CLOUD SYNC ONLY) ---
const getRawTradeKey = (trade: RawTrade): string => {
  const d = new Date(trade.Date);
  const normalizedDate = !isNaN(d.getTime()) ? d.toISOString().split('T')[0] : String(trade.Date).trim();
  const amt = parseFloat(String(trade.Amount).replace(/[$,()]/g, ''));
  const normalizedAmount = isNaN(amt) ? String(trade.Amount).trim() : amt.toFixed(2);

  return [
    normalizedDate,
    String(trade.Action).trim(),
    String(trade.Symbol).trim(),
    String(trade.Account).trim(),
    normalizedAmount,
    String(trade.Quantity).trim()
  ].join('|');
};

// Autocomplete Component
const AutocompleteInput = ({ value, onChange, options, placeholder, disabled, id, label }: any) => {
  const [showOptions, setShowOptions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const filteredOptions = useMemo(() =>
    options.filter((option: string) =>
      option.toLowerCase().includes(value.toLowerCase())
    ), [value, options]);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowOptions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  return (
    <div className="relative" ref={wrapperRef}>
      {label && <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">{label}</label>}
      <input
        id={id}
        type="text"
        placeholder={placeholder}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onFocus={() => setShowOptions(true)}
        className="block w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs"
        disabled={disabled}
      />
      {showOptions && filteredOptions.length > 0 && (
        <ul className="absolute z-30 w-full bg-white border border-gray-200 rounded-md mt-1 shadow-xl max-h-60 overflow-y-auto ring-1 ring-black ring-opacity-5">
          {filteredOptions.map((option: string) => (
            <li
              key={option}
              className="px-4 py-2 text-xs text-gray-700 cursor-pointer hover:bg-indigo-600 hover:text-white transition-colors"
              onMouseDown={() => {
                onChange(option);
                setShowOptions(false);
              }}
            >
              {option}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

type DatePreset = 'custom' | 'current_month' | 'current_year' | 'last_year' | 'all';

function App() {
  const [rawCsvData, setRawCsvData] = useState<RawTrade[]>([]);
  const [parsedTrades, setParsedTrades] = useState<ParsedTrade[]>([]);
  const [closedTrades, setClosedTrades] = useState<ClosedTrade[]>([]);
  const [unmatchedTrades, setUnmatchedTrades] = useState<ParsedTrade[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [loadingAction, setLoadingAction] = useState<'parsing' | 'loadingSheet' | 'savingSheet' | null>(null);

  const [isSignedIn, setIsSignedIn] = useState(false);
  const [userProfile, setUserProfile] = useState<{ name: string; email: string; picture: string } | null>(null);
  const [accessToken, setAccessToken] = useState<string | null>(null);
  const [saveMessage, setSaveMessage] = useState<string | null>(null);
  const [lastImportDate, setLastImportDate] = useState<string | null>(() => localStorage.getItem(STORAGE_KEY_LAST_IMPORT));

  // Dashboard logic states
  const [baseFund, setBaseFund] = useState<number>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_BASE_FUND);
    return saved ? parseFloat(saved) : 10000;
  });
  const [filterAccount, setFilterAccount] = useState<string>('ALL');
  const [filterStock, setFilterStock] = useState<string>('');
  const [filterOptionType, setFilterOptionType] = useState<OptionType | 'ALL'>('ALL');
  const [filterStartDate, setFilterStartDate] = useState<string>('');
  const [filterEndDate, setFilterEndDate] = useState<string>('');
  const [selectedDatePreset, setSelectedDatePreset] = useState<DatePreset>('current_month');
  const [globalSearchTerm, setGlobalSearchTerm] = useState<string>('');
  const [selectedMonth, setSelectedMonth] = useState<string | null>(null);

  const hasLoadedInitially = useRef(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_BASE_FUND, baseFund.toString());
  }, [baseFund]);

  const handleSignOut = useCallback(() => {
    if (accessToken) revokeAccessToken(accessToken);
    setIsSignedIn(false);
    setUserProfile(null);
    setAccessToken(null);
    localStorage.removeItem(STORAGE_KEY_TOKEN);
    localStorage.removeItem(STORAGE_KEY_USER);
  }, [accessToken]);

  const handleLoadFromSheet = useCallback(async (tokenToUse?: string) => {
    const activeToken = tokenToUse || accessToken;
    if (!activeToken) return;

    setIsLoading(true);
    setLoadingAction('loadingSheet');
    setError(null);
    try {
      const data = await fetchRawTradesFromSheet(activeToken);
      if (data && data.length > 0) {
        setRawCsvData(data);
        const now = new Date().toLocaleString();
        setLastImportDate(now);
        localStorage.setItem(STORAGE_KEY_LAST_IMPORT, now);
      }
    } catch (e: any) {
      if (e.message.includes('401') || e.message.includes('unauthorized')) {
        handleSignOut();
      } else {
        setError(`Failed to load data from sheet: ${e.message}`);
      }
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
    }
  }, [accessToken, handleSignOut]);

  const handleTokenResponse = useCallback(async (tokenResponse: any) => {
    if (tokenResponse && tokenResponse.access_token) {
      const token = tokenResponse.access_token;
      setAccessToken(token);
      setIsSignedIn(true);
      localStorage.setItem(STORAGE_KEY_TOKEN, token);
      try {
        const profile = await fetchUserProfile(token);
        setUserProfile(profile);
        localStorage.setItem(STORAGE_KEY_USER, JSON.stringify(profile));
      } catch (e) {
        console.error("Failed to fetch user profile", e);
      }
    }
  }, []);

  useEffect(() => {
    initGoogleClient(handleTokenResponse).catch(err => console.error(err));
    const storedToken = localStorage.getItem(STORAGE_KEY_TOKEN);
    const storedUser = localStorage.getItem(STORAGE_KEY_USER);
    if (storedToken && storedUser) {
      setAccessToken(storedToken);
      setIsSignedIn(true);
      setUserProfile(JSON.parse(storedUser));
      fetchUserProfile(storedToken).catch(() => handleSignOut());
    }
  }, [handleTokenResponse, handleSignOut]);

  useEffect(() => {
    if (isSignedIn && accessToken && !hasLoadedInitially.current) {
      hasLoadedInitially.current = true;
      handleLoadFromSheet(accessToken);
    }
  }, [isSignedIn, accessToken, handleLoadFromSheet]);

  const handleSignIn = () => requestAccessToken();

  const handleDataParsed = (newData: RawTrade[]) => {
    setRawCsvData(prevData => [...prevData, ...newData]);
    setError(null);
    const now = new Date().toLocaleString();
    setLastImportDate(now);
    localStorage.setItem(STORAGE_KEY_LAST_IMPORT, now);
  };

  const handleSaveToSheet = async () => {
    if (!rawCsvData.length || !accessToken) return;
    setIsLoading(true);
    setLoadingAction('savingSheet');
    setSaveMessage('Checking for new data...');
    try {
      const sheetData = await fetchRawTradesFromSheet(accessToken);
      const sheetCounts: Record<string, number> = {};
      sheetData.forEach(t => {
        const k = getRawTradeKey(t);
        sheetCounts[k] = (sheetCounts[k] || 0) + 1;
      });
      const localCounts: Record<string, number> = {};
      const newTrades: RawTrade[] = [];
      rawCsvData.forEach(trade => {
        const key = getRawTradeKey(trade);
        localCounts[key] = (localCounts[key] || 0) + 1;
        if (localCounts[key] > (sheetCounts[key] || 0)) {
          newTrades.push(trade);
        }
      });
      if (newTrades.length === 0) {
        setSaveMessage('No new trades to save.');
        return;
      }
      const result = await saveRawTradesToSheet(newTrades, accessToken);
      if (result.status === 'success') {
        setSaveMessage(`Successfully saved ${newTrades.length} new trades.`);
      } else {
        throw new Error(result.message);
      }
    } catch (e: any) {
      setSaveMessage(`Error: ${e.message}`);
    } finally {
      setIsLoading(false);
      setLoadingAction(null);
      setTimeout(() => setSaveMessage(null), 5000);
    }
  };

  useEffect(() => {
    if (rawCsvData.length > 0) {
      setParsedTrades(parseTrades(rawCsvData));
    } else {
      setParsedTrades([]);
    }
  }, [rawCsvData]);

  useEffect(() => {
    if (parsedTrades.length > 0) {
      const { closedTrades: cTrades, openPositions: oPositions, unmatchedCloses: uCloses } = processClosedTrades(parsedTrades);
      setClosedTrades(cTrades);
      setUnmatchedTrades([...oPositions, ...uCloses].sort((a, b) => a.originalDate.getTime() - b.originalDate.getTime()));
    } else {
      setClosedTrades([]);
      setUnmatchedTrades([]);
    }
  }, [parsedTrades]);

  // Date Preset logic
  useEffect(() => {
    const today = new Date();
    today.setUTCHours(0, 0, 0, 0);

    let start = '';
    let end = '';

    switch (selectedDatePreset) {
      case 'current_month':
        const sm = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), 1));
        const em = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + 1, 0));
        start = formatDateToISO(sm);
        end = formatDateToISO(em);
        break;
      case 'current_year':
        const sy = new Date(Date.UTC(today.getUTCFullYear(), 0, 1));
        const ey = new Date(Date.UTC(today.getUTCFullYear(), 11, 31));
        start = formatDateToISO(sy);
        end = formatDateToISO(ey);
        break;
      case 'last_year':
        const sly = new Date(Date.UTC(today.getUTCFullYear() - 1, 0, 1));
        const ely = new Date(Date.UTC(today.getUTCFullYear() - 1, 11, 31));
        start = formatDateToISO(sly);
        end = formatDateToISO(ely);
        break;
      case 'all':
        start = '';
        end = '';
        break;
      default:
        return;
    }
    setFilterStartDate(start);
    setFilterEndDate(end);
  }, [selectedDatePreset]);

  const availableAccounts = useMemo(() => Array.from(new Set(rawCsvData.map(t => t.Account))).sort(), [rawCsvData]);
  const availableStocks = useMemo(() => Array.from(new Set(closedTrades.map(t => t.stockName))).sort(), [closedTrades]);

  const primaryFilteredTrades = useMemo(() => {
    let currentTrades = closedTrades;
    const lowerCaseGlobalSearch = globalSearchTerm.toLowerCase();

    if (lowerCaseGlobalSearch) {
        currentTrades = currentTrades.filter(trade => 
            Object.values(trade).some(val => String(val).toLowerCase().includes(lowerCaseGlobalSearch))
        );
    }
    if (filterAccount !== 'ALL') currentTrades = currentTrades.filter(t => t.account === filterAccount);
    if (filterStock) currentTrades = currentTrades.filter(t => t.stockName.toLowerCase().includes(filterStock.toLowerCase()));
    if (filterOptionType !== 'ALL') currentTrades = currentTrades.filter(t => t.optionType === filterOptionType);

    const startStr = filterStartDate;
    const endStr = filterEndDate;

    if (startStr || endStr) {
      currentTrades = currentTrades.filter(trade => {
        const d = new Date(trade.closeDate);
        d.setUTCHours(0, 0, 0, 0);
        const tradeTime = d.getTime();

        const matchesStart = !startStr || tradeTime >= new Date(startStr).getTime();
        const matchesEnd = !endStr || tradeTime <= new Date(endStr).getTime();
        return matchesStart && matchesEnd;
      });
    }
    return currentTrades;
  }, [closedTrades, globalSearchTerm, filterAccount, filterStock, filterOptionType, filterStartDate, filterEndDate]);

  const finalFilteredTradesForTable = useMemo(() => {
    if (!selectedMonth) return primaryFilteredTrades;
    return primaryFilteredTrades.filter(trade => {
        const ym = `${trade.closeDate.getUTCFullYear()}-${(trade.closeDate.getUTCMonth() + 1).toString().padStart(2, '0')}`;
        return ym === selectedMonth;
    });
  }, [primaryFilteredTrades, selectedMonth]);

  const filteredSummary = useMemo(() => calculateSummary(finalFilteredTradesForTable), [finalFilteredTradesForTable]);

  const filteredUnmatchedTrades = useMemo(() => {
    if (filterAccount === 'ALL') return unmatchedTrades;
    return unmatchedTrades.filter(t => t.account === filterAccount);
  }, [unmatchedTrades, filterAccount]);

  const portfolioReturnPercent = useMemo(() => {
    if (!baseFund || baseFund === 0) return 0;
    return (filteredSummary.totalPnL / baseFund) * 100;
  }, [filteredSummary.totalPnL, baseFund]);

  const clearFilters = () => {
    setGlobalSearchTerm(''); 
    setFilterAccount('ALL'); 
    setFilterStock(''); 
    setFilterOptionType('ALL'); 
    setFilterStartDate(''); 
    setFilterEndDate(''); 
    setSelectedMonth(null);
    setSelectedDatePreset('all');
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-indigo-50 p-4 sm:p-6 lg:p-8">
      <header className="bg-white rounded-2xl shadow-sm border border-slate-200 p-4 mb-6 flex flex-col sm:flex-row justify-between items-center transition-all duration-300">
        <div className="flex items-center">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center mr-3 shadow-indigo-200 shadow-lg">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"></path></svg>
          </div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">Option Intelligence</h1>
        </div>
        <div className="flex items-center space-x-4">
          {isSignedIn && userProfile ? (
            <div className="flex items-center space-x-3 bg-slate-50 px-4 py-1.5 rounded-full border border-slate-100 shadow-sm">
              <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-slate-800 leading-tight">{userProfile.name}</p>
                <p className="text-[10px] text-indigo-500 font-bold">{userProfile.email}</p>
              </div>
              <img src={userProfile.picture} alt="avatar" className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
              <button onClick={handleSignOut} className="text-[10px] font-black text-slate-400 hover:text-indigo-600 uppercase tracking-widest transition-colors ml-1">Logout</button>
            </div>
          ) : (
            <button onClick={handleSignIn} className="flex items-center px-4 py-2 bg-white border border-slate-200 rounded-full shadow-sm text-xs font-black text-slate-700 hover:bg-slate-50 hover:border-indigo-300 transition-all uppercase tracking-wider">
              <img src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png" className="w-4 h-4 mr-2" alt="Google" />
              Sign in
            </button>
          )}
        </div>
      </header>

      <section className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
        <FileUpload 
          onDataParsed={handleDataParsed}
          isLoading={isLoading && loadingAction === 'parsing'}
          setIsLoading={(val) => { setIsLoading(val); if(val) setLoadingAction('parsing'); else setLoadingAction(null); }}
          setError={setError}
          existingAccounts={availableAccounts}
          lastImportDate={lastImportDate}
        />
        <div className="bg-white p-6 rounded-2xl shadow-sm flex flex-col justify-center items-center text-center relative overflow-hidden border border-slate-200">
          <div className="absolute top-0 right-0 p-3">
            {isLoading && loadingAction === 'loadingSheet' && (
              <div className="flex space-x-1">
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                <div className="w-2.5 h-2.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
              </div>
            )}
          </div>
          <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center mb-4 text-indigo-600 shadow-inner">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"></path></svg>
          </div>
          <h3 className="text-lg font-black mb-1 text-slate-800 uppercase tracking-tight">Cloud Warehouse</h3>
          <p className="text-xs text-slate-500 mb-5 font-medium">Sync trades with your centralized Google Sheet</p>
          <div className="flex space-x-3 w-full max-w-xs">
            <button 
              onClick={() => handleLoadFromSheet()} 
              disabled={!isSignedIn || isLoading}
              className="flex-1 px-4 py-2.5 bg-indigo-600 text-white text-xs font-black rounded-xl hover:bg-indigo-700 disabled:bg-slate-200 disabled:text-slate-400 shadow-md transition-all active:transform active:scale-95 uppercase tracking-wider"
            >
              {loadingAction === 'loadingSheet' ? 'Syncing...' : 'Fetch All'}
            </button>
            <button 
              onClick={handleSaveToSheet} 
              disabled={isLoading || !rawCsvData.length || !isSignedIn} 
              className="flex-1 px-4 py-2.5 bg-white text-indigo-600 border-2 border-indigo-600 text-xs font-black rounded-xl hover:bg-indigo-50 disabled:border-slate-100 disabled:text-slate-300 transition-all shadow-sm uppercase tracking-wider"
            >
              Push New
            </button>
          </div>
          {saveMessage && <p className="mt-3 text-[10px] font-black text-indigo-700 bg-indigo-50 px-3 py-1 rounded-full animate-pulse uppercase tracking-wider">{saveMessage}</p>}
        </div>
      </section>

      {error && (
        <div className="bg-rose-50 border-l-4 border-rose-500 p-4 rounded-r-2xl mb-6 flex items-center justify-between shadow-sm animate-in slide-in-from-top duration-300">
          <div className="flex items-center">
            <svg className="h-6 w-6 text-rose-500 mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path></svg>
            <p className="text-sm text-rose-800 font-bold">{error}</p>
          </div>
          <button onClick={() => setError(null)} className="text-rose-400 hover:text-rose-600 transition-colors">
            <svg className="h-5 w-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>
      )}

      {(rawCsvData.length > 0 || isLoading) ? (
        <>
          <section className="bg-white p-6 rounded-2xl shadow-sm mb-8 border border-slate-200 overflow-visible">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-8 gap-4">
              <div className="lg:col-span-1 bg-indigo-50/50 p-2 rounded-xl border border-indigo-100">
                <label className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1.5 block">Base Fund ($)</label>
                <input 
                  type="number" 
                  className="w-full px-2 py-1.5 bg-white border border-indigo-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs font-bold text-indigo-700 transition-all" 
                  value={baseFund} 
                  onChange={e => setBaseFund(Math.max(0, parseFloat(e.target.value) || 0))} 
                  placeholder="Initial Capital"
                />
              </div>
              <div className="relative group lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Search</label>
                <div className="relative">
                  <input type="text" className="w-full pl-9 pr-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs" value={globalSearchTerm} onChange={e => setGlobalSearchTerm(e.target.value)} placeholder="Symbol, P&L..." />
                  <svg className="w-3.5 h-3.5 text-gray-400 absolute left-3 top-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                </div>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Account</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={filterAccount} onChange={e => setFilterAccount(e.target.value)}>
                  <option value="ALL">All Accounts</option>
                  {availableAccounts.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>
              <div className="lg:col-span-1">
                <AutocompleteInput 
                  label="Symbol"
                  value={filterStock} 
                  onChange={setFilterStock} 
                  options={availableStocks} 
                  placeholder="Stock" 
                  id="stock-filter" 
                />
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Option Type</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={filterOptionType} onChange={e => setFilterOptionType(e.target.value as any)}>
                  <option value="ALL">All Types</option>
                  <option value={OptionType.CALL}>Calls</option>
                  <option value={OptionType.PUT}>Puts</option>
                </select>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Quick Filter</label>
                <select className="w-full px-3 py-2.5 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-xs appearance-none cursor-pointer" value={selectedDatePreset} onChange={e => setSelectedDatePreset(e.target.value as any)}>
                  <option value="all">All Time</option>
                  <option value="current_month">Current Month</option>
                  <option value="current_year">Current Year</option>
                  <option value="last_year">Last Year</option>
                  <option value="custom">Custom Range</option>
                </select>
              </div>
              <div className="lg:col-span-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1.5 block">Start - End</label>
                <div className="flex space-x-2">
                  <input type="date" className="w-1/2 p-2 bg-gray-50 border border-gray-200 rounded-lg text-[10px] focus:ring-2 focus:ring-indigo-500 outline-none" value={filterStartDate} onChange={e => {setFilterStartDate(e.target.value); setSelectedDatePreset('custom');}} />
                  <input type="date" className="w-1/2 p-2 bg-gray-50 border border-gray-200 rounded-lg text-[10px] focus:ring-2 focus:ring-indigo-500 outline-none" value={filterEndDate} onChange={e => {setFilterEndDate(e.target.value); setSelectedDatePreset('custom');}} />
                </div>
              </div>
              <div className="flex items-end lg:col-span-1">
