        MM/DD/YYYY Compliant • Financial Dashboard v2.3.2
      </footer>
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { RawTrade } from '../types';

declare const Papa: any;

interface FileUploadProps {
  onDataParsed: (data: RawTrade[]) => void;
  isLoading: boolean;
  setIsLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;
  existingAccounts: string[];
  lastImportDate: string | null;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataParsed, setIsLoading, isLoading, setError, existingAccounts, lastImportDate }) => {
  const [accountName, setAccountName] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [showAccountOptions, setShowAccountOptions] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const filteredAccountOptions = useMemo(() => 
    existingAccounts.filter(acc => acc.toLowerCase().includes(accountName.toLowerCase())),
    [existingAccounts, accountName]
  );

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setShowAccountOptions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      setSelectedFile(file);
    }
  };

  const handleParse = () => {
    if (!selectedFile) {
      setError("Please select a file to upload.");
      return;
    }
    if (!accountName.trim()) {
      setError("Please select or enter an account name.");
      return;
    }

    setIsLoading(true);
    setError(null);

    Papa.parse(selectedFile, {
      header: true,
      skipEmptyLines: true,
      complete: (results: { data: Omit<RawTrade, 'Account'>[]; errors: any[]; meta: any }) => {
        if (results.errors.length) {
          console.error("CSV parsing errors:", results.errors);
          setError(`Error parsing CSV: ${results.errors[0].message}`);
          setIsLoading(false);
          return;
        }

        // Add the account name to each parsed row
        const dataWithAccount = results.data.map(row => ({
          ...row,
          Account: accountName.trim()
        }));

        onDataParsed(dataWithAccount);
        setIsLoading(false);
        // Reset after successful parse
        setAccountName('');
        setSelectedFile(null);
        // Clear the file input visually
        const fileInput = document.getElementById('csv-upload') as HTMLInputElement;
        if (fileInput) fileInput.value = '';
      },
      error: (err: Error) => {
        console.error("PapaParse error:", err);
        setError(`Failed to read file: ${err.message}`);
        setIsLoading(false);
      }
    });
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
      <div className="flex justify-between items-start mb-5">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600">
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
          </div>
          <h2 className="text-lg font-black text-slate-800 uppercase tracking-tight">Import New Data</h2>
        </div>
        {lastImportDate && (
          <div className="text-right">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none">Last Import</p>
            <p className="text-[10px] font-bold text-indigo-600 tracking-tight">{lastImportDate}</p>
          </div>
        )}
      </div>

      <div className="space-y-4">
        <div className="relative">
          <label className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.2em] mb-1.5 block">Target Account</label>
          <div ref={dropdownRef} className="relative">
            <input 
              type="text"
              value={accountName}
              onChange={(e) => setAccountName(e.target.value)}
              onFocus={() => setShowAccountOptions(true)}
              placeholder="Select or type new account..."
              className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:bg-white outline-none transition-all text-xs font-bold text-slate-700"
              disabled={isLoading}
            />
            <div className="absolute right-3 top-3 text-slate-400 pointer-events-none">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7"></path></svg>
            </div>

            {showAccountOptions && (
              <div className="absolute z-20 w-full bg-white border border-slate-200 rounded-xl mt-2 shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 ring-1 ring-black ring-opacity-5">
                <div className="max-h-48 overflow-y-auto py-1">
                  {filteredAccountOptions.length > 0 ? (
                    filteredAccountOptions.map((acc) => (
                      <button
                        key={acc}
                        className="w-full text-left px-4 py-2.5 text-xs text-slate-700 hover:bg-indigo-600 hover:text-white transition-colors flex items-center"
                        onClick={() => {
                          setAccountName(acc);
                          setShowAccountOptions(false);
                        }}
                      >
                        <svg className="w-3 h-3 mr-2 opacity-50" fill="currentColor" viewBox="0 0 20 20"><path d="M7 3a1 1 0 000 2h6a1 1 0 100-2H7zM4 7a1 1 0 011-1h10a1 1 0 110 2H5a1 1 0 01-1-1zM2 11a2 2 0 012-2h12a2 2 0 012 2v4a2 2 0 01-2 2H4a2 2 0 01-2-2v-4z"></path></svg>
                        {acc}
                      </button>
                    ))
                  ) : (
                    <div className="px-4 py-2.5 text-xs text-slate-400 italic">No existing accounts match...</div>
                  )}
                </div>
                {accountName.trim() && !existingAccounts.includes(accountName.trim()) && (
                  <div className="border-t border-slate-100 p-2 bg-slate-50">
                    <button
                      className="w-full text-left px-2 py-1.5 text-[10px] text-indigo-600 font-black uppercase tracking-widest hover:bg-white rounded-lg transition-all"
                      onClick={() => setShowAccountOptions(false)}
                    >
                      + Create "{accountName}"
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center justify-center w-full">
          <label htmlFor="csv-upload" className={`flex flex-col items-center justify-center w-full h-32 border-2 border-dashed rounded-xl cursor-pointer transition-all ${selectedFile ? 'border-indigo-500 bg-indigo-50/30' : 'border-slate-200 bg-slate-50 hover:border-indigo-300 hover:bg-indigo-50/10'}`}>
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
              <svg className={`w-8 h-8 mb-2 transition-colors ${selectedFile ? 'text-indigo-600' : 'text-slate-400'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"></path></svg>
              <p className="mb-1 text-xs font-black text-slate-700 uppercase tracking-tight">
                {selectedFile ? selectedFile.name : 'Click to select CSV'}
              </p>
              <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Standard Broker CSV</p>
            </div>
            <input id="csv-upload" type="file" className="hidden" accept=".csv" onChange={handleFileChange} />
          </label>
        </div>

        <button 
          onClick={handleParse} 
          disabled={isLoading || !selectedFile || !accountName.trim()}
          className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-lg hover:bg-indigo-700 disabled:bg-slate-100 disabled:text-slate-400 transition-all active:scale-95 uppercase tracking-widest text-xs flex items-center justify-center"
        >
          {isLoading ? (
            <div className="flex items-center">
              <svg className="animate-spin h-4 w-4 mr-3 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
              Parsing Records...
            </div>
          ) : 'Load Selected Data'}
        </button>
      </div>
    </div>
  );
};

export default FileUpload;

